#[derive(Debug, Clone)]
enum SecretStoreBackend {
    Keychain,
    Memory(Arc<StdRwLock<HashMap<String, String>>>),
}

#[derive(Debug, Clone)]
struct SecretStore {
    service_name: String,
    backend: SecretStoreBackend,
}

impl SecretStore {
    fn from_env() -> Self {
        let service_name = std::env::var("CARSINOS_SECRET_SERVICE")
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| "carsinos".to_string());
        let mode = std::env::var("CARSINOS_SECRET_STORE")
            .unwrap_or_else(|_| {
                if cfg!(test) {
                    "memory".to_string()
                } else {
                    "keychain".to_string()
                }
            })
            .trim()
            .to_ascii_lowercase();
        if mode == "memory" {
            return Self {
                service_name,
                backend: SecretStoreBackend::Memory(Arc::new(StdRwLock::new(HashMap::new()))),
            };
        }
        Self {
            service_name,
            backend: SecretStoreBackend::Keychain,
        }
    }

    fn mode_name(&self) -> &'static str {
        match self.backend {
            SecretStoreBackend::Keychain => "keychain",
            SecretStoreBackend::Memory(_) => "memory",
        }
    }

    fn set_json(&self, secret_ref: &str, payload: &serde_json::Value) -> AnyResult<()> {
        let secret =
            serde_json::to_string(payload).context("failed to serialize secret payload")?;
        self.set_raw(secret_ref, &secret)
    }

    fn get_json(&self, secret_ref: &str) -> AnyResult<Option<serde_json::Value>> {
        let Some(secret) = self.get_raw(secret_ref)? else {
            return Ok(None);
        };
        let value: serde_json::Value = serde_json::from_str(&secret)
            .with_context(|| format!("failed to parse secret payload for ref {secret_ref}"))?;
        Ok(Some(value))
    }

    fn delete(&self, secret_ref: &str) -> AnyResult<()> {
        match &self.backend {
            SecretStoreBackend::Keychain => {
                let entry = keyring::Entry::new(&self.service_name, secret_ref)
                    .context("failed to initialize keychain entry")?;
                entry.set_password("").with_context(|| {
                    format!("failed clearing keychain secret for ref {secret_ref}")
                })?;
                Ok(())
            }
            SecretStoreBackend::Memory(store) => {
                let mut guard = store
                    .write()
                    .map_err(|_| anyhow::anyhow!("memory secret store poisoned"))?;
                guard.remove(secret_ref);
                Ok(())
            }
        }
    }

    fn set_raw(&self, secret_ref: &str, secret: &str) -> AnyResult<()> {
        match &self.backend {
            SecretStoreBackend::Keychain => {
                let entry = keyring::Entry::new(&self.service_name, secret_ref)
                    .context("failed to initialize keychain entry")?;
                entry.set_password(secret).with_context(|| {
                    format!("failed storing keychain secret for ref {secret_ref}")
                })?;
                Ok(())
            }
            SecretStoreBackend::Memory(store) => {
                let mut guard = store
                    .write()
                    .map_err(|_| anyhow::anyhow!("memory secret store poisoned"))?;
                guard.insert(secret_ref.to_string(), secret.to_string());
                Ok(())
            }
        }
    }

    fn get_raw(&self, secret_ref: &str) -> AnyResult<Option<String>> {
        match &self.backend {
            SecretStoreBackend::Keychain => {
                let entry = keyring::Entry::new(&self.service_name, secret_ref)
                    .context("failed to initialize keychain entry")?;
                match entry.get_password() {
                    Ok(secret) => {
                        if secret.is_empty() {
                            Ok(None)
                        } else {
                            Ok(Some(secret))
                        }
                    }
                    Err(keyring::Error::NoEntry) => Ok(None),
                    Err(err) => Err(anyhow::anyhow!(
                        "failed reading keychain secret for ref {secret_ref}: {err}"
                    )),
                }
            }
            SecretStoreBackend::Memory(store) => {
                let guard = store
                    .read()
                    .map_err(|_| anyhow::anyhow!("memory secret store poisoned"))?;
                Ok(guard.get(secret_ref).cloned())
            }
        }
    }
}

#[derive(Debug, Clone, Deserialize)]
struct OpenAiTokenExchangeResponse {
    access_token: String,
    #[serde(default)]
    refresh_token: Option<String>,
    #[serde(default)]
    expires_in: Option<i64>,
}

#[tokio::main]
async fn main() -> AnyResult<()> {
    let config = GatewayConfig::load_from_env()?;
    let auth_mode = load_auth_mode_from_env()?;
    let jwt_auth = load_jwt_auth_from_env(auth_mode)?;
    let trusted_proxy_headers = bool_env("CARSINOS_TRUST_PROXY_HEADERS", false);
    let trusted_proxy_allowlist = load_trusted_proxy_allowlist_from_env();
    let rate_limiter = Arc::new(RequestRateLimiter::from_env());
    let scheduler_instance = Arc::new(acquire_scheduler_instance_lock(&config.state_dir)?);
    enforce_network_exposure_policy(&config, trusted_proxy_headers, &trusted_proxy_allowlist)?;
    let paths = AppPaths::from_root(config.state_dir.clone());
    let _log_guards = init_tracing(&paths.logs_dir)?;

    carsinos_storage::init(&paths)?;
    let storage = Storage::from_paths(&paths);
    let runtime_config = load_runtime_config_from_storage(&storage)?;
    validate_runtime_config(&runtime_config)
        .context("runtime config validation failed at startup")?;
    let (trust_contract_lock_record, trust_contract_lock_path) =
        load_or_bootstrap_runtime_trust_contract_lock(&config.state_dir, &runtime_config)?;
    enforce_runtime_global_against_trust_lock(&runtime_config.global, &trust_contract_lock_record)
        .context("runtime config trust contract mismatch at startup")?;
    let providers = ProviderRegistry::new();
    let provider_models_http_client = reqwest::Client::builder()
        .timeout(Duration::from_secs(15))
        .build()
        .context("failed to build provider models http client")?;
    let plugin_manifest_dirs = load_plugin_manifest_dirs_from_env(&config.state_dir);
    let plugin_registry =
        PluginRegistry::load_from_dirs(&plugin_manifest_dirs).with_context(|| {
            let display = plugin_manifest_dirs
                .iter()
                .map(|path| path.display().to_string())
                .collect::<Vec<_>>()
                .join(", ");
            format!("failed to load plugin manifests from configured directories: {display}")
        })?;
    let plugin_count = plugin_registry.len();
    let extension_policy = Arc::new(ExtensionSecurityPolicy::from_env());
    let (hook_bus, hook_policy_denials) =
        build_hook_bus_from_registry(&plugin_registry, extension_policy.as_ref())?;
    let skill_dirs = load_skill_dirs_from_env(&config.state_dir);
    let mut skill_registry = SkillRegistry::load_from_dirs(&skill_dirs).with_context(|| {
        let display = skill_dirs
            .iter()
            .map(|path| path.display().to_string())
            .collect::<Vec<_>>()
            .join(", ");
        format!("failed to load skills from configured directories: {display}")
    })?;
    let skill_overrides = load_skill_state_overrides(&storage)?;
    skill_registry.apply_enabled_overrides(&skill_overrides);
    let skill_count = skill_registry.len();
    let tool_registry = Arc::new(ToolRegistry::from_env());
    let tool_concurrency_limit = usize_env("CARSINOS_TOOL_MAX_CONCURRENCY", 32).clamp(1, 512);
    let tool_concurrency = Arc::new(Semaphore::new(tool_concurrency_limit));
    let channel_tool_allowed_providers = Arc::new(load_channel_tool_allowed_providers_from_env());
    let tool_runner = LocalToolRunner::default();
    let secret_store = SecretStore::from_env();
    let channel_runtime = Arc::new(ChannelRuntimeManager::default_with_storage(
        storage.clone(),
        secret_store.clone(),
    ));
    let oauth_sessions = Arc::new(RwLock::new(HashMap::new()));
    let numquam_client = NumquamClient::from_env()?;
    let (event_tx, _) = broadcast::channel(256);
    let operator_allowlist = load_operator_allowlist_from_env();
    let operator_allowlist_entries = operator_allowlist.len();
    if let Some(client) = numquam_client.as_ref() {
        info!(
            transport = client.transport.as_str(),
            integration_base_url = %client.integration_base_url,
            mcp_url = %client.mcp_url,
            timeout_ms = client.request_timeout.as_millis() as u64,
            token_configured = client.token.is_some(),
            "Numquam integration client enabled"
        );
    }
    info!(
        plugin_count,
        plugin_manifest_dirs = ?plugin_manifest_dirs,
        hook_count = hook_bus.list_registrations().len(),
        hook_policy_denials = hook_policy_denials.len(),
        skill_count,
        tool_registry_entries = tool_registry.len(),
        tool_concurrency_limit,
        channel_tool_allowed_providers = ?channel_tool_allowed_providers,
        skill_dirs = ?skill_dirs,
        trust_lock_path = %trust_contract_lock_path.display(),
        trust_lock_hash = %trust_contract_lock_record.trust_hash,
        extension_plugin_allowlist_enabled = extension_policy.plugin_allowlist_enabled,
        "extension registries initialized"
    );

    let state = AppState {
        auth_mode,
        auth_token: Arc::new(config.token.clone()),
        jwt_auth: jwt_auth.map(Arc::new),
        jwt_replay_jti: Arc::new(StdRwLock::new(HashMap::new())),
        rate_limiter,
        trusted_proxy_headers,
        trusted_proxy_allowlist: Arc::new(trusted_proxy_allowlist),
        operator_allowlist: Arc::new(operator_allowlist),
        provider_models_http_client,
        provider_models_cache: Arc::new(RwLock::new(HashMap::new())),
        providers,
        tool_registry: tool_registry.clone(),
        tool_concurrency: tool_concurrency.clone(),
        channel_tool_allowed_providers: channel_tool_allowed_providers.clone(),
        channel_runtime: channel_runtime.clone(),
        internal_channel_ingest_token: Arc::new(uuid::Uuid::new_v4().to_string()),
        tool_runner,
        secret_store: secret_store.clone(),
        oauth_sessions,
        numquam_client,
        numquam_runtime_status: Arc::new(RwLock::new(NumquamRuntimeStatus::default())),
        plugin_registry: Arc::new(RwLock::new(plugin_registry)),
        hook_bus: Arc::new(hook_bus),
        skill_registry: Arc::new(RwLock::new(skill_registry)),
        extension_policy: extension_policy.clone(),
        storage,
        metrics: Arc::new(GatewayMetrics::default()),
        event_tx,
        event_seq: Arc::new(AtomicU64::new(1)),
        started_at: Utc::now(),
        started_instant: Instant::now(),
        db_path: Arc::new(paths.db_path.display().to_string()),
        attachments_path: Arc::new(paths.attachments_dir.display().to_string()),
        session_run_lanes: Arc::new(SessionRunLaneManager::default()),
        tool_error_breaker: Arc::new(ToolErrorFingerprintBreaker::default()),
        plugin_runtime_health: Arc::new(StdRwLock::new(HashMap::new())),
        plugin_daemons: Arc::new(RwLock::new(HashMap::new())),
        scheduler_instance: scheduler_instance.clone(),
        trust_contract_lock: Arc::new(RwLock::new(trust_contract_lock_record)),
        trust_contract_lock_path: Arc::new(trust_contract_lock_path.display().to_string()),
        state_dir: Arc::new(config.state_dir.clone()),
    };
    record_extension_hook_policy_denials(&state, &hook_policy_denials);
    state.channel_runtime.start_all();

    if scheduler_instance.enabled {
        let scheduler_state = state.clone();
        tokio::spawn(async move {
            scheduler_loop(scheduler_state).await;
        });
    } else {
        warn!(
            lock_path = %scheduler_instance.lock_path,
            owner = %scheduler_instance.owner,
            detail = ?scheduler_instance.detail,
            "scheduler disabled: lock is held by another process"
        );
    }
    let channel_runtime_state = state.channel_runtime.clone();
    tokio::spawn(async move {
        channel_runtime_supervisor_loop(channel_runtime_state).await;
    });
    let channel_listener_state = state.clone();
    tokio::spawn(async move {
        channel_ingest_listener_loop(channel_listener_state).await;
    });
    refresh_numquam_handshake_state(&state).await;
    let numquam_handshake_state = state.clone();
    tokio::spawn(async move {
        numquam_handshake_loop(numquam_handshake_state).await;
    });

    let app = build_app(state);

    let listener = tokio::net::TcpListener::bind(config.bind).await?;

    info!(
        bind = %config.bind,
        state_dir = %config.state_dir.display(),
        auth_mode = %match auth_mode {
            AuthMode::StaticBearer => "static_bearer",
            AuthMode::Jwt => "jwt",
        },
        trusted_proxy_headers,
        secret_store = secret_store.mode_name(),
        operator_allowlist_entries,
        scheduler_running = scheduler_instance.enabled,
        scheduler_lock_path = %scheduler_instance.lock_path,
        scheduler_lock_owner = %scheduler_instance.owner,
        "carsinos gateway starting"
    );

    if auth_mode == AuthMode::StaticBearer && config.token_source == TokenSource::Generated {
        warn!(token = %config.token, "CARSINOS_GATEWAY_TOKEN not set; generated runtime token");
    }

    axum::serve(listener, app)
        .with_graceful_shutdown(shutdown_signal())
        .await?;

    Ok(())
}

async fn root() -> &'static str {
    "carsinOS gateway is running"
}

async fn health(
    headers: HeaderMap,
    State(state): State<AppState>,
) -> std::result::Result<impl IntoResponse, StatusCode> {
    let auth_ctx = require_bearer_auth(&headers, &state).map_err(|err| err.status)?;
    require_roles_raw(&auth_ctx, &[ROLE_OPERATOR_ADMIN, ROLE_OPERATOR_READONLY])
        .map_err(|err| err.status)?;
    let db_ok = state.storage.ping().is_ok();
    if !db_ok {
        warn!("health check degraded: sqlite ping failed");
    }

    let response = HealthResponse {
        ok: db_ok,
        service: "carsinos-gateway".to_string(),
        version: env!("CARGO_PKG_VERSION").to_string(),
        uptime_ms: state.started_instant.elapsed().as_millis() as u64,
        now_utc: Utc::now(),
    };

    if db_ok {
        Ok((StatusCode::OK, Json(response)))
    } else {
        Ok((StatusCode::SERVICE_UNAVAILABLE, Json(response)))
    }
}

async fn status(
    headers: HeaderMap,
    State(state): State<AppState>,
) -> std::result::Result<impl IntoResponse, StatusCode> {
    let auth_ctx = require_bearer_auth(&headers, &state).map_err(|err| err.status)?;
    require_roles_raw(&auth_ctx, &[ROLE_OPERATOR_ADMIN, ROLE_OPERATOR_READONLY])
        .map_err(|err| err.status)?;
    let runtime_config = load_runtime_config(&state).map_err(|err| {
        error!(error = %err, "failed loading runtime config for status endpoint");
        StatusCode::INTERNAL_SERVER_ERROR
    })?;
    let autonomy_guardrails = runtime_config.autonomy_guardrails.clone();
    let numquam = current_numquam_status(&state, Some(&runtime_config)).await;
    let trust_lock = state.trust_contract_lock.read().await.clone();
    let trust_hash = runtime_trust_contract_hash(&runtime_config.global).map_err(|err| {
        error!(error = %err, "failed hashing runtime trust contract for status endpoint");
        StatusCode::INTERNAL_SERVER_ERROR
    })?;
    let trust_contract_lock = RuntimeTrustContractLockSummaryResponse {
        enforced: true,
        lock_path: (*state.trust_contract_lock_path).clone(),
        trust_hash: trust_lock.trust_hash.clone(),
        locked_at: trust_lock.locked_at,
        drift_detected: trust_hash != trust_lock.trust_hash,
    };
    let (circuit_breakers, open_circuit_breakers) = collect_breaker_summary(&state, 64, None)
        .map_err(|err| {
            error!(error = %err, "failed loading circuit breaker summary for status endpoint");
            StatusCode::INTERNAL_SERVER_ERROR
        })?;
    let top_stop_reasons = collect_top_stop_reasons_from_jobs(&state, 10).map_err(|err| {
        error!(error = %err, "failed loading top stop reasons for status endpoint");
        StatusCode::INTERNAL_SERVER_ERROR
    })?;
    let plugin_breakers = plugin_runtime_status_items(&state, true).await;
    let open_plugin_breakers = plugin_breakers
        .iter()
        .filter(|item| {
            item.disabled_until_ms
                .map(|value| value > current_time_ms())
                .unwrap_or(false)
        })
        .count() as u64;

    let response = StatusResponse {
        service: "carsinos-gateway".to_string(),
        version: env!("CARGO_PKG_VERSION").to_string(),
        started_at_utc: state.started_at,
        uptime_ms: state.started_instant.elapsed().as_millis() as u64,
        db_path: (*state.db_path).clone(),
        attachments_path: (*state.attachments_path).clone(),
        trust_contract_lock,
        scheduler_lock: scheduler_lock_state_response(&state),
        autonomy_guardrails,
        numquam,
        open_circuit_breakers,
        circuit_breakers,
        open_plugin_breakers,
        plugin_breakers,
        top_stop_reasons,
    };

    Ok(Json(response))
}

async fn metrics(
    headers: HeaderMap,
    State(state): State<AppState>,
) -> std::result::Result<impl IntoResponse, StatusCode> {
    let auth_ctx = require_bearer_auth(&headers, &state).map_err(|err| err.status)?;
    require_roles_raw(&auth_ctx, &[ROLE_OPERATOR_ADMIN, ROLE_OPERATOR_READONLY])
        .map_err(|err| err.status)?;
    let response = MetricsResponse {
        service: "carsinos-gateway".to_string(),
        version: env!("CARGO_PKG_VERSION").to_string(),
        uptime_ms: state.started_instant.elapsed().as_millis() as u64,
        requests_total: state.metrics.requests_total.load(Ordering::Relaxed),
        auth_failures_total: state.metrics.auth_failures_total.load(Ordering::Relaxed),
        runs_started_total: state.metrics.runs_started_total.load(Ordering::Relaxed),
        runs_succeeded_total: state.metrics.runs_succeeded_total.load(Ordering::Relaxed),
        runs_failed_total: state.metrics.runs_failed_total.load(Ordering::Relaxed),
        notes_created_total: state.metrics.notes_created_total.load(Ordering::Relaxed),
        notes_updated_total: state.metrics.notes_updated_total.load(Ordering::Relaxed),
    };
    Ok(Json(response))
}

async fn list_provider_capabilities(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<ListProviderCapabilitiesQuery>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    let provider_filter = query
        .provider
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(|value| value.to_ascii_lowercase());
    let resource = provider_filter
        .as_ref()
        .map(|provider| format!("provider:{provider}"))
        .unwrap_or_else(|| "providers".to_string());
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_OPERATOR_READONLY],
        "provider.capabilities.list",
        &resource,
    )?;

    let capabilities = if let Some(provider) = provider_filter.as_deref() {
        vec![state.providers.capabilities(provider).ok_or_else(|| {
            api_error(
                StatusCode::BAD_REQUEST,
                "unsupported provider for capabilities query",
            )
        })?]
    } else {
        state.providers.list_capabilities()
    };

    let items = capabilities
        .into_iter()
        .map(|item| ProviderCapabilityResponse {
            provider: item.provider,
            supports_streaming: item.supports_streaming,
            supports_tools: item.supports_tools,
            supports_json_mode: item.supports_json_mode,
            supports_vision: item.supports_vision,
            max_context_tokens: item.max_context_tokens,
            error_classes: item.error_classes,
            retryable_error_classes: item.retryable_error_classes,
        })
        .collect::<Vec<_>>();
    Ok(Json(ListProviderCapabilitiesResponse {
        contract_version: "v2".to_string(),
        items,
    }))
}

async fn list_provider_models(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<ListProviderModelsQuery>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    let provider = query.provider.trim().to_ascii_lowercase();
    if provider.is_empty() {
        return Err(api_error_with_code(
            StatusCode::BAD_REQUEST,
            "INVALID_INPUT",
            "provider is required",
        ));
    }
    if !provider_models_supported(&provider) {
        return Err(api_error_with_code(
            StatusCode::BAD_REQUEST,
            "INVALID_INPUT",
            "unsupported provider for model catalog",
        ));
    }

    let requested_auth_profile_id = query
        .auth_profile_id
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(|value| value.to_string());
    let resource = requested_auth_profile_id
        .as_ref()
        .map(|id| format!("provider:{provider}:auth_profile:{id}"))
        .unwrap_or_else(|| format!("provider:{provider}"));
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_OPERATOR_READONLY],
        "provider.models.list",
        &resource,
    )?;
    require_endpoint_rate_limit_with_error(&state, &auth, "run")?;

    let requested_agent_id = query
        .agent_id
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(|value| value.to_string());
    let refresh = query.refresh.unwrap_or(false);

    let resolved_auth_record = resolve_provider_models_auth_profile(
        &state,
        &provider,
        requested_agent_id.as_deref(),
        requested_auth_profile_id.as_deref(),
    )
    .await
    .map_err(map_provider_models_auth_resolution_error)?;
    let resolved_auth_profile_id = resolved_auth_record
        .as_ref()
        .map(|profile| profile.auth_profile_id.clone());
    let resolved_auth_profile = match resolved_auth_record.as_ref() {
        Some(profile) => Some(to_provider_auth_profile(&state, profile).map_err(|err| {
            internal_err_with_error("hydrating auth profile for model catalog failed", err)
        })?),
        None => None,
    };

    let base_url = provider_models_base_url(&provider, resolved_auth_profile.as_ref());
    let cache_key =
        provider_models_cache_key(&provider, &base_url, resolved_auth_profile_id.as_deref());
    let now = current_time_ms();
    if !refresh {
        if let Some(entry) = state
            .provider_models_cache
            .read()
            .await
            .get(&cache_key)
            .cloned()
        {
            if entry.expires_at_ms > now {
                return Ok(Json(ListProviderModelsResponse {
                    contract_version: PROVIDER_MODELS_CONTRACT_VERSION.to_string(),
                    provider,
                    auth_profile_id: entry.auth_profile_id,
                    items: entry.items,
                }));
            }
        }
    }

    let items = fetch_provider_models_from_upstream(
        &state,
        &provider,
        &base_url,
        resolved_auth_profile.as_ref(),
    )
    .await?;
    state.provider_models_cache.write().await.insert(
        cache_key,
        ProviderModelsCacheEntry {
            auth_profile_id: resolved_auth_profile_id.clone(),
            items: items.clone(),
            expires_at_ms: now.saturating_add(PROVIDER_MODELS_CACHE_TTL_MS),
        },
    );

    Ok(Json(ListProviderModelsResponse {
        contract_version: PROVIDER_MODELS_CONTRACT_VERSION.to_string(),
        provider,
        auth_profile_id: resolved_auth_profile_id,
        items,
    }))
}

async fn resolve_provider_models_auth_profile(
    state: &AppState,
    provider: &str,
    requested_agent_id: Option<&str>,
    requested_auth_profile_id: Option<&str>,
) -> AnyResult<Option<AuthProfileRecord>> {
    if provider_requires_auth(provider) {
        let candidates = resolve_run_auth_profiles(
            state,
            provider,
            requested_agent_id.unwrap_or_default(),
            requested_auth_profile_id,
        )
        .await?;
        return Ok(candidates.into_iter().flatten().next());
    }

    let Some(profile_id) = requested_auth_profile_id else {
        return Ok(None);
    };
    if state.storage.global_kill_switch_active()? {
        anyhow::bail!("AUTH_FORBIDDEN:global kill-switch active");
    }
    if state.storage.provider_kill_switch_active(provider)? {
        anyhow::bail!("AUTH_FORBIDDEN:provider kill-switch active");
    }

    let profile = state
        .storage
        .get_auth_profile(profile_id)?
        .with_context(|| format!("requested auth profile not found: {profile_id}"))?;
    if profile.provider != provider {
        anyhow::bail!(
            "requested auth profile provider mismatch: expected '{}' got '{}'",
            provider,
            profile.provider
        );
    }
    if !profile.enabled {
        anyhow::bail!("requested auth profile is disabled: {profile_id}");
    }
    if profile.kill_switch_scope == KILL_SWITCH_SCOPE_PROFILE {
        anyhow::bail!("requested auth profile is kill-switched at profile scope");
    }
    if !provider_auth_mode_allowed(provider, &profile.auth_mode) {
        anyhow::bail!(
            "requested auth profile mode '{}' not allowed for provider '{}'",
            profile.auth_mode,
            provider
        );
    }
    let policy = auth_mode_policy(&profile.auth_mode)
        .with_context(|| format!("unsupported auth_mode in profile: {}", profile.auth_mode))?;
    if profile.risk_level != policy.risk_level {
        anyhow::bail!(
            "requested auth profile risk_level '{}' mismatches registry '{}'",
            profile.risk_level,
            policy.risk_level
        );
    }
    if policy.requires_kill_switch && profile.kill_switch_scope == KILL_SWITCH_SCOPE_NONE {
        anyhow::bail!("requested high-risk auth profile is missing kill-switch scope");
    }
    let profile = maybe_refresh_expired_auth_profile(state, profile).await?;
    if auth_profile_credentials_expired(&profile)? {
        anyhow::bail!("requested auth profile credentials expired");
    }
    Ok(Some(profile))
}

fn map_provider_models_auth_resolution_error(err: anyhow::Error) -> (StatusCode, Json<ApiError>) {
    let message = err.to_string();
    let normalized = message.to_ascii_lowercase();
    if message.starts_with("AUTH_FORBIDDEN:")
        || normalized.contains("kill-switch")
        || normalized.contains("kill switch")
    {
        return api_error_with_code(
            StatusCode::FORBIDDEN,
            "AUTH_FORBIDDEN",
            &format!("provider auth policy denied model catalog request: {message}"),
        );
    }
    api_error_with_code(
        StatusCode::BAD_GATEWAY,
        "AUTH_REQUIRED",
        &format!("provider auth unavailable for model catalog request: {message}"),
    )
}

fn provider_models_supported(provider: &str) -> bool {
    matches!(
        provider,
        "openai" | "anthropic" | "openrouter" | "ollama" | "vllm" | "mock"
    )
}

fn provider_models_default_base_url(provider: &str) -> &'static str {
    match provider {
        "openai" => OPENAI_DEFAULT_API_BASE,
        "anthropic" => ANTHROPIC_DEFAULT_API_BASE,
        "openrouter" => OPENROUTER_DEFAULT_API_BASE,
        "ollama" => OLLAMA_DEFAULT_API_BASE,
        "vllm" => VLLM_DEFAULT_API_BASE,
        "mock" => "mock://local",
        _ => "mock://local",
    }
}

fn provider_models_base_url(provider: &str, profile: Option<&ProviderAuthProfile>) -> String {
    profile
        .and_then(|item| item.api_base_url.as_ref())
        .map(|value| value.trim().trim_end_matches('/').to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| provider_models_default_base_url(provider).to_string())
}

fn provider_models_cache_key(
    provider: &str,
    base_url: &str,
    auth_profile_id: Option<&str>,
) -> String {
    format!(
        "{}|{}|{}",
        provider.to_ascii_lowercase(),
        base_url.to_ascii_lowercase(),
        auth_profile_id.unwrap_or("<none>")
    )
}

fn truncate_provider_error_body(raw: &str) -> String {
    let trimmed = raw.trim();
    if trimmed.is_empty() {
        "<empty>".to_string()
    } else if trimmed.len() > 240 {
        trimmed.chars().take(240).collect::<String>()
    } else {
        trimmed.to_string()
    }
}

fn extract_provider_auth_token(profile: &ProviderAuthProfile) -> AnyResult<Option<String>> {
    let payload: serde_json::Value = serde_json::from_str(&profile.credentials_json)
        .context("failed to parse provider credentials for model catalog")?;
    for key in ["api_key", "token", "access_token", "bearer_token"] {
        if let Some(value) = payload.get(key).and_then(|value| value.as_str()) {
            let trimmed = value.trim();
            if !trimmed.is_empty() {
                return Ok(Some(trimmed.to_string()));
            }
        }
    }
    Ok(None)
}

fn parse_openai_models_payload(payload: &serde_json::Value) -> AnyResult<Vec<String>> {
    let Some(items) = payload.get("data").and_then(|value| value.as_array()) else {
        anyhow::bail!("missing data array in provider models response");
    };
    let mut model_ids = Vec::new();
    for item in items {
        let candidate = item
            .get("id")
            .and_then(|value| value.as_str())
            .or_else(|| item.get("name").and_then(|value| value.as_str()))
            .unwrap_or_default()
            .trim()
            .to_string();
        if !candidate.is_empty() {
            model_ids.push(candidate);
        }
    }
    Ok(model_ids)
}

fn parse_ollama_models_payload(payload: &serde_json::Value) -> AnyResult<Vec<String>> {
    let Some(items) = payload.get("models").and_then(|value| value.as_array()) else {
        anyhow::bail!("missing models array in ollama tags response");
    };
    let mut model_ids = Vec::new();
    for item in items {
        let candidate = item
            .get("name")
            .and_then(|value| value.as_str())
            .or_else(|| item.get("model").and_then(|value| value.as_str()))
            .unwrap_or_default()
            .trim()
            .to_string();
        if !candidate.is_empty() {
            model_ids.push(candidate);
        }
    }
    Ok(model_ids)
}

fn normalize_provider_models(raw: Vec<String>) -> Vec<ProviderModelResponse> {
    let mut seen = HashSet::new();
    let mut items = Vec::new();
    for model_id in raw {
        let trimmed = model_id.trim();
        if trimmed.is_empty() {
            continue;
        }
        if !seen.insert(trimmed.to_string()) {
            continue;
        }
        items.push(ProviderModelResponse {
            model_id: trimmed.to_string(),
            label: trimmed.to_string(),
        });
    }
    items
}

async fn fetch_provider_models_from_upstream(
    state: &AppState,
    provider: &str,
    base_url: &str,
    auth_profile: Option<&ProviderAuthProfile>,
) -> std::result::Result<Vec<ProviderModelResponse>, (StatusCode, Json<ApiError>)> {
    if provider == "mock" {
        return Ok(vec![ProviderModelResponse {
            model_id: "mock-echo-v1".to_string(),
            label: "mock-echo-v1".to_string(),
        }]);
    }

    let token = match auth_profile {
        Some(profile) => extract_provider_auth_token(profile).map_err(|err| {
            internal_err_with_error(
                "extracting provider auth token for model catalog failed",
                err,
            )
        })?,
        None => None,
    };
    let provider_requires_token = matches!(provider, "openai" | "anthropic" | "openrouter");
    if provider_requires_token && token.is_none() {
        return Err(api_error_with_code(
            StatusCode::BAD_GATEWAY,
            "AUTH_REQUIRED",
            "provider auth profile is missing API token",
        ));
    }

    let normalized_base = base_url.trim_end_matches('/');
    let mut request = match provider {
        "openai" | "openrouter" | "vllm" => state
            .provider_models_http_client
            .get(format!("{normalized_base}/v1/models")),
        "anthropic" => state
            .provider_models_http_client
            .get(format!("{normalized_base}/v1/models"))
            .header("anthropic-version", "2023-06-01"),
        "ollama" => state
            .provider_models_http_client
            .get(format!("{normalized_base}/api/tags")),
        _ => {
            return Err(api_error_with_code(
                StatusCode::BAD_REQUEST,
                "INVALID_INPUT",
                "unsupported provider for model catalog",
            ));
        }
    };
    if let Some(token) = token {
        if provider == "anthropic" {
            request = request.header("x-api-key", token);
        } else {
            request = request.bearer_auth(token);
        }
    }

    let response = request.send().await.map_err(|err| {
        if err.is_timeout() {
            api_error_with_code(
                StatusCode::GATEWAY_TIMEOUT,
                "TIMEOUT",
                "provider model catalog request timed out",
            )
        } else {
            api_error_with_code(
                StatusCode::SERVICE_UNAVAILABLE,
                "DEPENDENCY_UNAVAILABLE",
                "provider model catalog request failed",
            )
        }
    })?;
    let status = response.status();
    if !status.is_success() {
        let body = response.text().await.unwrap_or_default();
        let body = truncate_provider_error_body(&body);
        if matches!(status, StatusCode::UNAUTHORIZED | StatusCode::FORBIDDEN) {
            return Err(api_error_with_code(
                StatusCode::BAD_GATEWAY,
                "AUTH_REQUIRED",
                &format!(
                    "provider auth rejected model catalog request (status={} body={body})",
                    status.as_u16()
                ),
            ));
        }
        if status == StatusCode::TOO_MANY_REQUESTS {
            return Err(api_error_with_code(
                StatusCode::TOO_MANY_REQUESTS,
                "RATE_LIMITED",
                &format!(
                    "provider model catalog request was rate limited (status={} body={body})",
                    status.as_u16()
                ),
            ));
        }
        if matches!(
            status,
            StatusCode::REQUEST_TIMEOUT | StatusCode::GATEWAY_TIMEOUT
        ) {
            return Err(api_error_with_code(
                StatusCode::GATEWAY_TIMEOUT,
                "TIMEOUT",
                &format!(
                    "provider model catalog request timed out (status={} body={body})",
                    status.as_u16()
                ),
            ));
        }
        return Err(api_error_with_code(
            StatusCode::SERVICE_UNAVAILABLE,
            "DEPENDENCY_UNAVAILABLE",
            &format!(
                "provider model catalog request failed (status={} body={body})",
                status.as_u16()
            ),
        ));
    }

    let payload: serde_json::Value = response.json().await.map_err(|err| {
        api_error_with_code(
            StatusCode::SERVICE_UNAVAILABLE,
            "DEPENDENCY_UNAVAILABLE",
            &format!("failed to parse provider model catalog response: {err}"),
        )
    })?;
    let raw_models = match provider {
        "openai" | "openrouter" | "anthropic" | "vllm" => parse_openai_models_payload(&payload)
            .map_err(|err| {
                api_error_with_code(
                    StatusCode::SERVICE_UNAVAILABLE,
                    "DEPENDENCY_UNAVAILABLE",
                    &format!("invalid provider model catalog payload: {err}"),
                )
            })?,
        "ollama" => parse_ollama_models_payload(&payload).map_err(|err| {
            api_error_with_code(
                StatusCode::SERVICE_UNAVAILABLE,
                "DEPENDENCY_UNAVAILABLE",
                &format!("invalid provider model catalog payload: {err}"),
            )
        })?,
        _ => unreachable!(),
    };
    Ok(normalize_provider_models(raw_models))
}

async fn list_tool_capabilities(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<ListToolCapabilitiesQuery>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_OPERATOR_READONLY],
        "tool.capabilities.list",
        "tools.capabilities",
    )?;

    let include_disabled = query.include_disabled.unwrap_or(false);
    let origin_filter = query
        .origin
        .as_ref()
        .map(|value| value.trim().to_ascii_lowercase())
        .filter(|value| !value.is_empty());

    let core_sandbox = ToolCapabilitySandboxResponse {
        allowed_roots: state
            .tool_runner
            .sandbox
            .allowed_roots
            .iter()
            .map(|path| path.display().to_string())
            .collect::<Vec<_>>(),
        network_policy: match state.tool_runner.sandbox.network_policy {
            carsinos_tools::ToolNetworkPolicy::Allowlist => "allowlist".to_string(),
            carsinos_tools::ToolNetworkPolicy::DenyAll => "deny_all".to_string(),
        },
        network_allowlist_count: state.tool_runner.sandbox.network_allowlist.len(),
    };

    let mut items = state
        .tool_registry
        .definitions
        .values()
        .map(|definition| ToolCapabilityResponse {
            tool_name: definition.tool_name.to_string(),
            origin: "core".to_string(),
            risk_level: definition.base_risk_level.to_string(),
            requires_approval: matches!(definition.approval_policy, ToolApprovalPolicy::Always),
            timeout_ms: definition.timeout_ms,
            enabled: true,
            sandbox: core_sandbox.clone(),
        })
        .collect::<Vec<_>>();

    for manifest in state.plugin_registry.read().await.list_manifests() {
        for tool in manifest.capabilities.tools {
            items.push(ToolCapabilityResponse {
                tool_name: tool.name,
                origin: format!("plugin:{}", manifest.plugin_id),
                risk_level: "high".to_string(),
                requires_approval: true,
                timeout_ms: manifest.limits.timeout_ms,
                enabled: manifest.enabled,
                sandbox: ToolCapabilitySandboxResponse {
                    allowed_roots: manifest.permissions.allowed_roots.clone(),
                    network_policy: manifest.permissions.network_policy.clone(),
                    network_allowlist_count: manifest.permissions.network_allowlist.len(),
                },
            });
        }
    }

    if !include_disabled {
        items.retain(|item| item.enabled);
    }
    if let Some(filter) = origin_filter.as_ref() {
        items.retain(|item| item.origin.to_ascii_lowercase() == *filter);
    }
    items.sort_by(|left, right| {
        left.origin
            .cmp(&right.origin)
            .then_with(|| left.tool_name.cmp(&right.tool_name))
    });

    Ok(Json(ListToolCapabilitiesResponse {
        contract_version: "tool.capabilities.v1".to_string(),
        items,
    }))
}

async fn list_plugins(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<ListPluginsQuery>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_OPERATOR_READONLY],
        "plugin.registry.list",
        "plugins",
    )?;

    let include_disabled = query.include_disabled.unwrap_or(false);
    let mut manifests = state.plugin_registry.read().await.list_manifests();
    if !include_disabled {
        manifests.retain(|manifest| manifest.enabled);
    }
    let items = manifests
        .into_iter()
        .map(to_plugin_manifest_response)
        .collect::<Vec<_>>();

    Ok(Json(ListPluginsResponse {
        contract_version: PLUGIN_REGISTRY_CONTRACT_VERSION.to_string(),
        plugin_api_version: PLUGIN_API_VERSION_V1.to_string(),
        items,
    }))
}

async fn plugin_runtime_status_items(
    state: &AppState,
    include_disabled: bool,
) -> Vec<PluginRuntimeStatusResponse> {
    let manifests = state.plugin_registry.read().await.list_manifests();
    let health = state
        .plugin_runtime_health
        .read()
        .expect("plugin runtime health read lock poisoned")
        .clone();
    manifests
        .into_iter()
        .filter(|manifest| include_disabled || manifest.enabled)
        .map(|manifest| {
            let entry = health.get(&manifest.plugin_id).cloned().unwrap_or_default();
            let now_ms = current_time_ms();
            let faulted = entry
                .disabled_until_ms
                .map(|value| value > now_ms)
                .unwrap_or(false)
                || entry.consecutive_failures > 0;
            PluginRuntimeStatusResponse {
                plugin_id: manifest.plugin_id,
                enabled: manifest.enabled,
                faulted,
                disabled_until_ms: entry.disabled_until_ms,
                consecutive_failures: entry.consecutive_failures,
                last_error_code: entry.last_error_code,
                last_error: entry.last_error,
                last_success_ms: entry.last_success_ms,
                last_invoked_ms: entry.last_invoked_ms,
            }
        })
        .collect::<Vec<_>>()
}

async fn list_plugin_runtime_status(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<ListPluginsQuery>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_OPERATOR_READONLY],
        "plugin.runtime_status.list",
        "plugins.runtime",
    )?;
    let items = plugin_runtime_status_items(&state, query.include_disabled.unwrap_or(false)).await;
    Ok(Json(ListPluginRuntimeStatusResponse {
        contract_version: PLUGIN_RUNTIME_STATUS_CONTRACT_VERSION.to_string(),
        items,
    }))
}

fn normalize_plugin_id(raw: &str) -> AnyResult<String> {
    let normalized = raw.trim().to_ascii_lowercase();
    if normalized.is_empty() {
        anyhow::bail!("plugin_id must not be empty");
    }
    if !normalized
        .chars()
        .all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '-' | '_' | '.'))
    {
        anyhow::bail!("plugin_id contains invalid characters");
    }
    Ok(normalized)
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct PluginVersionPointersRecord {
    schema_version: String,
    plugin_id: String,
    active_version: String,
    previous_version: Option<String>,
    updated_at: i64,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct PluginRunnerPermissionsEnvelope {
    allowed_roots: Vec<String>,
    network_policy: String,
    network_allowlist: Vec<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct PluginRunnerLimitsEnvelope {
    timeout_ms: u64,
    max_output_chars: usize,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct PluginRunnerRequestEnvelope {
    contract_version: String,
    request_id: String,
    kind: String,
    plugin_id: String,
    deadline_ms: u64,
    permissions: PluginRunnerPermissionsEnvelope,
    limits: PluginRunnerLimitsEnvelope,
    payload: serde_json::Value,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct PluginRunnerMetricsEnvelope {
    #[serde(default)]
    duration_ms: Option<u64>,
    #[serde(default)]
    output_chars: Option<usize>,
    #[serde(default)]
    timed_out: Option<bool>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct PluginRunnerResponseEnvelope {
    contract_version: String,
    request_id: String,
    status: String,
    #[serde(default)]
    result: Option<serde_json::Value>,
    #[serde(default)]
    error_code: Option<String>,
    #[serde(default)]
    error_message: Option<String>,
    #[serde(default)]
    metrics: Option<PluginRunnerMetricsEnvelope>,
}

#[derive(Debug, Clone)]
struct PluginInvokeResult {
    status: String,
    result: Option<serde_json::Value>,
    error_code: Option<String>,
    error_message: Option<String>,
    duration_ms: u64,
    output_chars: usize,
}

#[derive(Debug, Clone)]
struct PluginInvokeError {
    code: String,
    message: String,
    duration_ms: u64,
    breaker_open: bool,
}

#[derive(Debug, Clone)]
struct PluginHookInvocationOutcome {
    plugin_id: String,
    hook_name: String,
    status: String,
    error_code: Option<String>,
    error: Option<String>,
    duration_ms: u64,
    breaker_open: bool,
}

fn plugin_breaker_limit(runtime_config: &RuntimeConfigResponse) -> u64 {
    runtime_config
        .autonomy_guardrails
        .max_consecutive_failures_before_breaker
        .max(1)
}

fn plugin_runner_timeout_ms(manifest: &CorePluginManifest) -> u64 {
    manifest
        .limits
        .timeout_ms
        .unwrap_or(PLUGIN_RUNNER_DEFAULT_TIMEOUT_MS)
        .clamp(100, PLUGIN_RUNNER_MAX_TIMEOUT_MS)
}

fn plugin_runner_max_output_chars(manifest: &CorePluginManifest) -> usize {
    manifest
        .limits
        .max_output_chars
        .unwrap_or(PLUGIN_RUNNER_DEFAULT_OUTPUT_CHARS)
        .clamp(128, 1_000_000)
}

fn plugin_is_breaker_open(state: &AppState, plugin_id: &str, now_ms: i64) -> bool {
    state
        .plugin_runtime_health
        .read()
        .expect("plugin runtime health read lock poisoned")
        .get(plugin_id)
        .and_then(|item| item.disabled_until_ms)
        .map(|value| value > now_ms)
        .unwrap_or(false)
}

fn record_plugin_invoke_start(state: &AppState, plugin_id: &str, now_ms: i64) {
    let mut write = state
        .plugin_runtime_health
        .write()
        .expect("plugin runtime health write lock poisoned");
    let entry = write.entry(plugin_id.to_string()).or_default();
    entry.last_invoked_ms = Some(now_ms);
}

fn record_plugin_invoke_success(state: &AppState, plugin_id: &str, now_ms: i64) {
    let mut write = state
        .plugin_runtime_health
        .write()
        .expect("plugin runtime health write lock poisoned");
    let entry = write.entry(plugin_id.to_string()).or_default();
    entry.consecutive_failures = 0;
    entry.disabled_until_ms = None;
    entry.last_error_code = None;
    entry.last_error = None;
    entry.last_success_ms = Some(now_ms);
    entry.last_invoked_ms = Some(now_ms);
}

fn record_plugin_invoke_failure(
    state: &AppState,
    plugin_id: &str,
    now_ms: i64,
    error_code: Option<String>,
    error_message: Option<String>,
    breaker_limit: u64,
) -> bool {
    let mut write = state
        .plugin_runtime_health
        .write()
        .expect("plugin runtime health write lock poisoned");
    let entry = write.entry(plugin_id.to_string()).or_default();
    entry.consecutive_failures = entry.consecutive_failures.saturating_add(1);
    entry.last_error_code = error_code;
    entry.last_error = error_message;
    entry.last_invoked_ms = Some(now_ms);
    if entry.consecutive_failures >= breaker_limit {
        entry.disabled_until_ms = Some(now_ms.saturating_add(PLUGIN_BREAKER_COOLDOWN_MS));
        true
    } else {
        false
    }
}

fn plugin_storage_root_from_runtime(
    state: &AppState,
    runtime_config: &RuntimeConfigResponse,
) -> AnyResult<PathBuf> {
    let configured = runtime_config
        .extensions
        .plugin_bundle_root
        .as_ref()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    if let Some(raw_path) = configured {
        if raw_path.contains("://") {
            anyhow::bail!("extensions.plugin_bundle_root must be a local filesystem path");
        }
        let raw = PathBuf::from(raw_path);
        if raw.is_absolute() {
            return Ok(raw);
        }
        return Ok(state.state_dir.join(raw));
    }
    Ok(state.state_dir.join("plugins"))
}

fn plugin_bundle_dir(
    plugin_storage_root: &FsPath,
    plugin_id: &str,
    plugin_version: &str,
) -> PathBuf {
    plugin_storage_root
        .join("bundles")
        .join(plugin_id)
        .join(plugin_version)
}

fn plugin_bundle_manifest_path(
    plugin_storage_root: &FsPath,
    plugin_id: &str,
    plugin_version: &str,
) -> PathBuf {
    plugin_bundle_dir(plugin_storage_root, plugin_id, plugin_version).join("manifest.json")
}

fn plugin_active_manifest_path(plugin_storage_root: &FsPath, plugin_id: &str) -> PathBuf {
    plugin_storage_root
        .join("active")
        .join(format!("{plugin_id}.json"))
}

fn plugin_pointer_path(plugin_storage_root: &FsPath, plugin_id: &str) -> PathBuf {
    plugin_storage_root
        .join("pointers")
        .join(format!("{plugin_id}.json"))
}

fn persist_json_atomic(path: &FsPath, payload: &str, context_label: &str) -> AnyResult<()> {
    let parent = path
        .parent()
        .ok_or_else(|| anyhow::anyhow!("invalid path for {context_label}"))?;
    std::fs::create_dir_all(parent).with_context(|| {
        format!(
            "failed to create parent directory for {context_label} {}",
            parent.display()
        )
    })?;
    let tmp_path = path.with_extension("tmp");
    std::fs::write(&tmp_path, payload).with_context(|| {
        format!(
            "failed writing temporary {context_label} file {}",
            tmp_path.display()
        )
    })?;
    std::fs::rename(&tmp_path, path)
        .with_context(|| format!("failed replacing {context_label} file {}", path.display()))?;
    Ok(())
}

fn persist_plugin_manifest(path: &FsPath, manifest: &CorePluginManifest) -> AnyResult<()> {
    let payload = serde_json::to_string_pretty(manifest)
        .map_err(|err| anyhow::anyhow!("failed serializing plugin manifest: {err}"))?;
    persist_json_atomic(path, &payload, "plugin manifest")
}

fn persist_plugin_pointer(path: &FsPath, pointer: &PluginVersionPointersRecord) -> AnyResult<()> {
    let payload = serde_json::to_string_pretty(pointer)
        .map_err(|err| anyhow::anyhow!("failed serializing plugin pointer: {err}"))?;
    persist_json_atomic(path, &payload, "plugin pointer")
}

fn load_plugin_pointer(path: &FsPath) -> AnyResult<Option<PluginVersionPointersRecord>> {
    if !path.exists() {
        return Ok(None);
    }
    let payload = std::fs::read_to_string(path)
        .with_context(|| format!("failed reading plugin pointer file {}", path.display()))?;
    let pointer: PluginVersionPointersRecord = serde_json::from_str(&payload)
        .with_context(|| format!("failed parsing plugin pointer file {}", path.display()))?;
    if pointer.schema_version.trim() != PLUGIN_POINTER_SCHEMA_VERSION {
        anyhow::bail!(
            "unsupported plugin pointer schema_version '{}' in {}",
            pointer.schema_version,
            path.display()
        );
    }
    Ok(Some(pointer))
}

fn load_bundle_manifest(
    plugin_storage_root: &FsPath,
    plugin_id: &str,
    plugin_version: &str,
) -> AnyResult<CorePluginManifest> {
    let path = plugin_bundle_manifest_path(plugin_storage_root, plugin_id, plugin_version);
    let payload = std::fs::read_to_string(&path)
        .with_context(|| format!("failed reading bundle manifest {}", path.display()))?;
    let manifest = serde_json::from_str::<CorePluginManifest>(&payload)
        .with_context(|| format!("failed parsing bundle manifest {}", path.display()))?;
    Ok(manifest)
}

fn sha256_file_hex(path: &FsPath) -> AnyResult<String> {
    let bytes = std::fs::read(path)
        .with_context(|| format!("failed reading file for sha256 {}", path.display()))?;
    let digest = Sha256::digest(bytes);
    Ok(format!("{digest:x}"))
}

fn normalize_local_source_path(raw: &str) -> AnyResult<PathBuf> {
    let trimmed = raw.trim();
    if trimmed.is_empty() {
        anyhow::bail!("artifact.local_path cannot be empty");
    }
    if trimmed.contains("://") {
        anyhow::bail!("artifact.local_path must reference a local filesystem path");
    }
    let candidate = PathBuf::from(trimmed);
    if candidate.is_absolute() {
        Ok(candidate)
    } else {
        Ok(std::env::current_dir()
            .context("failed resolving current_dir for artifact.local_path")?
            .join(candidate))
    }
}

fn ensure_plugin_tool_names_do_not_collide(manifest: &CorePluginManifest) -> AnyResult<()> {
    let reserved = RESERVED_CORE_TOOL_NAMES
        .iter()
        .copied()
        .collect::<HashSet<_>>();
    for tool in &manifest.capabilities.tools {
        if reserved.contains(tool.name.as_str()) {
            anyhow::bail!(
                "{}: plugin tool '{}' collides with reserved core tool name",
                EXT_PLUGIN_TOOL_NAME_COLLISION,
                tool.name
            );
        }
    }
    Ok(())
}

fn ensure_daemon_allowlist(
    runtime_config: &RuntimeConfigResponse,
    manifest: &CorePluginManifest,
) -> AnyResult<()> {
    if manifest.artifact.exec_kind != carsinos_core::PluginExecKind::Daemon {
        return Ok(());
    }
    let plugin_id = manifest.plugin_id.trim().to_ascii_lowercase();
    let allowlisted = runtime_config
        .extensions
        .plugin_daemon_allowlist
        .iter()
        .any(|entry| entry.trim().eq_ignore_ascii_case(&plugin_id));
    if !allowlisted {
        anyhow::bail!(
            "{}: plugin '{}' is not allowlisted for daemon execution",
            EXT_PLUGIN_DAEMON_NOT_ALLOWLISTED,
            plugin_id
        );
    }
    Ok(())
}

fn materialize_plugin_bundle(
    plugin_storage_root: &FsPath,
    manifest: &CorePluginManifest,
) -> AnyResult<CorePluginManifest> {
    let source_path = normalize_local_source_path(&manifest.artifact.local_path)?;
    if !source_path.exists() || !source_path.is_file() {
        anyhow::bail!(
            "artifact.local_path does not reference an existing file: {}",
            source_path.display()
        );
    }
    let expected_sha = manifest.artifact.sha256.trim().to_ascii_lowercase();
    let source_sha = sha256_file_hex(&source_path)?;
    if source_sha != expected_sha {
        anyhow::bail!(
            "{}: artifact digest mismatch for plugin '{}'",
            EXT_PLUGIN_SHA_MISMATCH,
            manifest.plugin_id
        );
    }

    let bundle_dir = plugin_bundle_dir(
        plugin_storage_root,
        manifest.plugin_id.as_str(),
        manifest.plugin_version.as_str(),
    );
    std::fs::create_dir_all(&bundle_dir).with_context(|| {
        format!(
            "failed creating plugin bundle directory {}",
            bundle_dir.display()
        )
    })?;
    let artifact_filename = source_path
        .file_name()
        .and_then(|value| value.to_str())
        .map(|value| value.to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| "artifact.bin".to_string());
    let bundled_artifact_path = bundle_dir.join(artifact_filename);
    std::fs::copy(&source_path, &bundled_artifact_path).with_context(|| {
        format!(
            "failed copying plugin artifact '{}' -> '{}'",
            source_path.display(),
            bundled_artifact_path.display()
        )
    })?;
    let bundled_sha = sha256_file_hex(&bundled_artifact_path)?;
    if bundled_sha != expected_sha {
        anyhow::bail!(
            "{}: copied artifact digest mismatch for plugin '{}'",
            EXT_PLUGIN_SHA_MISMATCH,
            manifest.plugin_id
        );
    }

    let mut materialized = manifest.clone();
    let source_display = source_path.display().to_string();
    materialized.artifact.local_path = bundled_artifact_path.display().to_string();
    if materialized.artifact.command.trim() == source_display {
        materialized.artifact.command = materialized.artifact.local_path.clone();
    }
    for arg in &mut materialized.artifact.args {
        if arg.trim() == source_display {
            *arg = materialized.artifact.local_path.clone();
        }
    }
    let bundle_manifest_path = plugin_bundle_manifest_path(
        plugin_storage_root,
        manifest.plugin_id.as_str(),
        manifest.plugin_version.as_str(),
    );
    persist_plugin_manifest(&bundle_manifest_path, &materialized)?;
    Ok(materialized)
}

fn parse_plugin_manifest_request(value: serde_json::Value) -> AnyResult<CorePluginManifest> {
    serde_json::from_value::<CorePluginManifest>(value).context("invalid plugin manifest payload")
}

fn hook_point_capability_name(hook_point: HookPoint) -> &'static str {
    match hook_point {
        HookPoint::RunStart => "run.start",
        HookPoint::RunEnd => "run.end",
        HookPoint::ToolBefore => "tool.before",
        HookPoint::ToolAfter => "tool.after",
        HookPoint::CompactionBefore => "compaction.before",
        HookPoint::CompactionAfter => "compaction.after",
    }
}

fn parse_plugin_runner_response_strict(payload: &str) -> AnyResult<PluginRunnerResponseEnvelope> {
    let trimmed = payload.trim();
    if trimmed.is_empty() {
        anyhow::bail!("plugin runner stdout was empty");
    }
    let mut deserializer = serde_json::Deserializer::from_str(trimmed);
    let mut parsed = PluginRunnerResponseEnvelope::deserialize(&mut deserializer)
        .context("plugin runner stdout was not valid json envelope")?;
    deserializer
        .end()
        .context("plugin runner stdout contained trailing non-json output")?;
    parsed.status = parsed.status.trim().to_ascii_lowercase();
    if parsed.contract_version.trim() != PLUGIN_RUNNER_CONTRACT_VERSION {
        anyhow::bail!(
            "unexpected plugin runner contract_version '{}'",
            parsed.contract_version.trim()
        );
    }
    if !matches!(parsed.status.as_str(), "ok" | "error" | "deny") {
        anyhow::bail!("unsupported plugin runner status '{}'", parsed.status);
    }
    Ok(parsed)
}

async fn invoke_plugin_runner_subprocess_impl(
    state: &AppState,
    manifest: &CorePluginManifest,
    kind: &str,
    payload: serde_json::Value,
) -> std::result::Result<PluginInvokeResult, PluginInvokeError> {
    let now_ms = current_time_ms();
    if plugin_is_breaker_open(state, &manifest.plugin_id, now_ms) {
        return Err(PluginInvokeError {
            code: EXT_PLUGIN_DISABLED.to_string(),
            message: format!("plugin '{}' is disabled by breaker", manifest.plugin_id),
            duration_ms: 0,
            breaker_open: true,
        });
    }
    record_plugin_invoke_start(state, &manifest.plugin_id, now_ms);

    let breaker_limit = load_runtime_config(state)
        .map(|config| plugin_breaker_limit(&config))
        .unwrap_or(3);
    let timeout_ms = plugin_runner_timeout_ms(manifest);
    let max_output_chars = plugin_runner_max_output_chars(manifest);
    let request_id = uuid::Uuid::new_v4().to_string();
    let request_envelope = PluginRunnerRequestEnvelope {
        contract_version: PLUGIN_RUNNER_CONTRACT_VERSION.to_string(),
        request_id: request_id.clone(),
        kind: kind.to_string(),
        plugin_id: manifest.plugin_id.clone(),
        deadline_ms: (current_time_ms().max(0) as u64).saturating_add(timeout_ms),
        permissions: PluginRunnerPermissionsEnvelope {
            allowed_roots: manifest.permissions.allowed_roots.clone(),
            network_policy: manifest.permissions.network_policy.clone(),
            network_allowlist: manifest.permissions.network_allowlist.clone(),
        },
        limits: PluginRunnerLimitsEnvelope {
            timeout_ms,
            max_output_chars,
        },
        payload,
    };
    let request_json = match serde_json::to_string(&request_envelope) {
        Ok(value) => value,
        Err(err) => {
            let message = format!("failed serializing plugin runner request: {err}");
            let tripped = record_plugin_invoke_failure(
                state,
                &manifest.plugin_id,
                current_time_ms(),
                Some(EXT_PLUGIN_SCHEMA_INVALID.to_string()),
                Some(message.clone()),
                breaker_limit,
            );
            return Err(PluginInvokeError {
                code: EXT_PLUGIN_SCHEMA_INVALID.to_string(),
                message,
                duration_ms: 0,
                breaker_open: tripped,
            });
        }
    };

    if manifest.artifact.command.trim().is_empty() {
        let message = "plugin manifest artifact.command cannot be empty".to_string();
        let tripped = record_plugin_invoke_failure(
            state,
            &manifest.plugin_id,
            current_time_ms(),
            Some(EXT_PLUGIN_SCHEMA_INVALID.to_string()),
            Some(message.clone()),
            breaker_limit,
        );
        return Err(PluginInvokeError {
            code: EXT_PLUGIN_SCHEMA_INVALID.to_string(),
            message,
            duration_ms: 0,
            breaker_open: tripped,
        });
    }

    let started = Instant::now();
    let mut command = tokio::process::Command::new(manifest.artifact.command.trim());
    command.args(manifest.artifact.args.iter().map(|value| value.trim()));
    command.kill_on_drop(true);
    command.stdin(std::process::Stdio::piped());
    command.stdout(std::process::Stdio::piped());
    command.stderr(std::process::Stdio::piped());
    command.env_clear();
    if let Some(path_env) = std::env::var_os("PATH") {
        command.env("PATH", path_env);
    }
    command.env("CARSINOS_PLUGIN_ID", manifest.plugin_id.as_str());
    command.env("CARSINOS_PLUGIN_KIND", kind);
    if let Some(parent) = PathBuf::from(&manifest.artifact.local_path)
        .parent()
        .map(PathBuf::from)
    {
        command.current_dir(parent);
    }

    let mut child = match command.spawn() {
        Ok(child) => child,
        Err(err) => {
            let message = format!("failed spawning plugin subprocess: {err}");
            let tripped = record_plugin_invoke_failure(
                state,
                &manifest.plugin_id,
                current_time_ms(),
                Some(EXT_PLUGIN_EXEC_FAILED.to_string()),
                Some(message.clone()),
                breaker_limit,
            );
            return Err(PluginInvokeError {
                code: EXT_PLUGIN_EXEC_FAILED.to_string(),
                message,
                duration_ms: started.elapsed().as_millis() as u64,
                breaker_open: tripped,
            });
        }
    };

    if let Some(mut stdin) = child.stdin.take() {
        if let Err(err) = stdin.write_all(request_json.as_bytes()).await {
            let message = format!("failed writing plugin request stdin: {err}");
            let tripped = record_plugin_invoke_failure(
                state,
                &manifest.plugin_id,
                current_time_ms(),
                Some(EXT_PLUGIN_EXEC_FAILED.to_string()),
                Some(message.clone()),
                breaker_limit,
            );
            return Err(PluginInvokeError {
                code: EXT_PLUGIN_EXEC_FAILED.to_string(),
                message,
                duration_ms: started.elapsed().as_millis() as u64,
                breaker_open: tripped,
            });
        }
        let _ = stdin.shutdown().await;
    }

    let output =
        match tokio::time::timeout(Duration::from_millis(timeout_ms), child.wait_with_output())
            .await
        {
            Ok(Ok(output)) => output,
            Ok(Err(err)) => {
                let message = format!("plugin subprocess wait failed: {err}");
                let tripped = record_plugin_invoke_failure(
                    state,
                    &manifest.plugin_id,
                    current_time_ms(),
                    Some(EXT_PLUGIN_EXEC_FAILED.to_string()),
                    Some(message.clone()),
                    breaker_limit,
                );
                return Err(PluginInvokeError {
                    code: EXT_PLUGIN_EXEC_FAILED.to_string(),
                    message,
                    duration_ms: started.elapsed().as_millis() as u64,
                    breaker_open: tripped,
                });
            }
            Err(_) => {
                let message = format!(
                    "plugin subprocess timed out after {}ms for '{}'",
                    timeout_ms, manifest.plugin_id
                );
                let tripped = record_plugin_invoke_failure(
                    state,
                    &manifest.plugin_id,
                    current_time_ms(),
                    Some(EXT_PLUGIN_TIMEOUT.to_string()),
                    Some(message.clone()),
                    breaker_limit,
                );
                return Err(PluginInvokeError {
                    code: EXT_PLUGIN_TIMEOUT.to_string(),
                    message,
                    duration_ms: started.elapsed().as_millis() as u64,
                    breaker_open: tripped,
                });
            }
        };

    if output.stdout.len() > max_output_chars {
        let message = format!(
            "plugin stdout exceeded {} chars for '{}'",
            max_output_chars, manifest.plugin_id
        );
        let tripped = record_plugin_invoke_failure(
            state,
            &manifest.plugin_id,
            current_time_ms(),
            Some(EXT_PLUGIN_OUTPUT_INVALID.to_string()),
            Some(message.clone()),
            breaker_limit,
        );
        return Err(PluginInvokeError {
            code: EXT_PLUGIN_OUTPUT_INVALID.to_string(),
            message,
            duration_ms: started.elapsed().as_millis() as u64,
            breaker_open: tripped,
        });
    }

    let stdout_text = match String::from_utf8(output.stdout) {
        Ok(text) => text,
        Err(err) => {
            let message = format!("plugin stdout is not utf-8: {err}");
            let tripped = record_plugin_invoke_failure(
                state,
                &manifest.plugin_id,
                current_time_ms(),
                Some(EXT_PLUGIN_OUTPUT_INVALID.to_string()),
                Some(message.clone()),
                breaker_limit,
            );
            return Err(PluginInvokeError {
                code: EXT_PLUGIN_OUTPUT_INVALID.to_string(),
                message,
                duration_ms: started.elapsed().as_millis() as u64,
                breaker_open: tripped,
            });
        }
    };
    let stderr_text = String::from_utf8_lossy(&output.stderr).to_string();
    let parsed = match parse_plugin_runner_response_strict(&stdout_text) {
        Ok(parsed) => parsed,
        Err(err) => {
            let message = if stderr_text.trim().is_empty() {
                format!("{}: {}", EXT_PLUGIN_OUTPUT_INVALID, err)
            } else {
                format!(
                    "{}: {}; stderr={}",
                    EXT_PLUGIN_OUTPUT_INVALID,
                    err,
                    stderr_text.trim()
                )
            };
            let tripped = record_plugin_invoke_failure(
                state,
                &manifest.plugin_id,
                current_time_ms(),
                Some(EXT_PLUGIN_OUTPUT_INVALID.to_string()),
                Some(message.clone()),
                breaker_limit,
            );
            return Err(PluginInvokeError {
                code: EXT_PLUGIN_OUTPUT_INVALID.to_string(),
                message,
                duration_ms: started.elapsed().as_millis() as u64,
                breaker_open: tripped,
            });
        }
    };
    if parsed.request_id != request_id {
        let message = format!(
            "plugin response request_id mismatch: expected {}, got {}",
            request_id, parsed.request_id
        );
        let tripped = record_plugin_invoke_failure(
            state,
            &manifest.plugin_id,
            current_time_ms(),
            Some(EXT_PLUGIN_SCHEMA_INVALID.to_string()),
            Some(message.clone()),
            breaker_limit,
        );
        return Err(PluginInvokeError {
            code: EXT_PLUGIN_SCHEMA_INVALID.to_string(),
            message,
            duration_ms: started.elapsed().as_millis() as u64,
            breaker_open: tripped,
        });
    }

    let duration_ms = started.elapsed().as_millis() as u64;
    let output_chars = stdout_text.chars().count();
    if parsed.status == "error" {
        let code = parsed
            .error_code
            .clone()
            .filter(|value| !value.trim().is_empty())
            .unwrap_or_else(|| EXT_PLUGIN_EXEC_FAILED.to_string());
        let message = parsed
            .error_message
            .clone()
            .filter(|value| !value.trim().is_empty())
            .unwrap_or_else(|| "plugin returned status=error".to_string());
        let tripped = record_plugin_invoke_failure(
            state,
            &manifest.plugin_id,
            current_time_ms(),
            Some(code.clone()),
            Some(message.clone()),
            breaker_limit,
        );
        return Err(PluginInvokeError {
            code,
            message,
            duration_ms,
            breaker_open: tripped,
        });
    }

    record_plugin_invoke_success(state, &manifest.plugin_id, current_time_ms());
    Ok(PluginInvokeResult {
        status: parsed.status,
        result: parsed.result,
        error_code: parsed.error_code,
        error_message: parsed.error_message,
        duration_ms,
        output_chars,
    })
}

async fn daemon_supervisor_for_plugin(
    state: &AppState,
    manifest: &CorePluginManifest,
) -> Arc<Mutex<PluginDaemonSupervisor>> {
    let plugin_id = manifest.plugin_id.clone();
    if let Some(existing) = state.plugin_daemons.read().await.get(&plugin_id).cloned() {
        return existing;
    }
    let mut write = state.plugin_daemons.write().await;
    write
        .entry(plugin_id)
        .or_insert_with(|| Arc::new(Mutex::new(PluginDaemonSupervisor::from_manifest(manifest))))
        .clone()
}

async fn reset_plugin_daemon_supervisor(state: &AppState, plugin_id: &str) {
    let removed = {
        let mut write = state.plugin_daemons.write().await;
        write.remove(plugin_id)
    };
    if let Some(supervisor) = removed {
        let mut guard = supervisor.lock().await;
        guard.stop().await;
    }
}

async fn invoke_plugin_runner_daemon(
    state: &AppState,
    manifest: &CorePluginManifest,
    kind: &str,
    payload: serde_json::Value,
) -> std::result::Result<PluginInvokeResult, PluginInvokeError> {
    let now_ms = current_time_ms();
    if plugin_is_breaker_open(state, &manifest.plugin_id, now_ms) {
        return Err(PluginInvokeError {
            code: EXT_PLUGIN_DISABLED.to_string(),
            message: format!("plugin '{}' is disabled by breaker", manifest.plugin_id),
            duration_ms: 0,
            breaker_open: true,
        });
    }
    record_plugin_invoke_start(state, &manifest.plugin_id, now_ms);

    let breaker_limit = load_runtime_config(state)
        .map(|config| plugin_breaker_limit(&config))
        .unwrap_or(3);
    let timeout_ms = plugin_runner_timeout_ms(manifest);
    let max_output_chars = plugin_runner_max_output_chars(manifest);
    let request_id = uuid::Uuid::new_v4().to_string();
    let request_envelope = PluginRunnerRequestEnvelope {
        contract_version: PLUGIN_RUNNER_CONTRACT_VERSION.to_string(),
        request_id: request_id.clone(),
        kind: kind.to_string(),
        plugin_id: manifest.plugin_id.clone(),
        deadline_ms: (current_time_ms().max(0) as u64).saturating_add(timeout_ms),
        permissions: PluginRunnerPermissionsEnvelope {
            allowed_roots: manifest.permissions.allowed_roots.clone(),
            network_policy: manifest.permissions.network_policy.clone(),
            network_allowlist: manifest.permissions.network_allowlist.clone(),
        },
        limits: PluginRunnerLimitsEnvelope {
            timeout_ms,
            max_output_chars,
        },
        payload,
    };
    let request_json =
        serde_json::to_string(&request_envelope).map_err(|err| PluginInvokeError {
            code: EXT_PLUGIN_SCHEMA_INVALID.to_string(),
            message: format!("failed serializing plugin daemon request: {err}"),
            duration_ms: 0,
            breaker_open: false,
        })?;

    let supervisor = daemon_supervisor_for_plugin(state, manifest).await;
    let started = Instant::now();
    let mut guard = supervisor.lock().await;
    if let Err(err) = guard.ensure_started(&manifest.plugin_id, kind).await {
        let tripped = record_plugin_invoke_failure(
            state,
            &manifest.plugin_id,
            current_time_ms(),
            Some(err.code.clone()),
            Some(err.message.clone()),
            breaker_limit,
        );
        return Err(PluginInvokeError {
            breaker_open: tripped,
            ..err
        });
    }
    if let Some(stdin) = guard.stdin.as_mut() {
        if let Err(err) = stdin
            .write_all(format!("{request_json}\n").as_bytes())
            .await
        {
            guard.stop().await;
            let message = format!("plugin daemon stdin write failed: {err}");
            let tripped = record_plugin_invoke_failure(
                state,
                &manifest.plugin_id,
                current_time_ms(),
                Some(EXT_PLUGIN_EXEC_FAILED.to_string()),
                Some(message.clone()),
                breaker_limit,
            );
            return Err(PluginInvokeError {
                code: EXT_PLUGIN_EXEC_FAILED.to_string(),
                message,
                duration_ms: started.elapsed().as_millis() as u64,
                breaker_open: tripped,
            });
        }
        if let Err(err) = stdin.flush().await {
            guard.stop().await;
            let message = format!("plugin daemon stdin flush failed: {err}");
            let tripped = record_plugin_invoke_failure(
                state,
                &manifest.plugin_id,
                current_time_ms(),
                Some(EXT_PLUGIN_EXEC_FAILED.to_string()),
                Some(message.clone()),
                breaker_limit,
            );
            return Err(PluginInvokeError {
                code: EXT_PLUGIN_EXEC_FAILED.to_string(),
                message,
                duration_ms: started.elapsed().as_millis() as u64,
                breaker_open: tripped,
            });
        }
    } else {
        guard.stop().await;
        let message = "plugin daemon stdin missing".to_string();
        let tripped = record_plugin_invoke_failure(
            state,
            &manifest.plugin_id,
            current_time_ms(),
            Some(EXT_PLUGIN_EXEC_FAILED.to_string()),
            Some(message.clone()),
            breaker_limit,
        );
        return Err(PluginInvokeError {
            code: EXT_PLUGIN_EXEC_FAILED.to_string(),
            message,
            duration_ms: started.elapsed().as_millis() as u64,
            breaker_open: tripped,
        });
    }

    let mut line = String::new();
    let read_result = {
        let Some(stdout) = guard.stdout.as_mut() else {
            guard.stop().await;
            let message = "plugin daemon stdout missing".to_string();
            let tripped = record_plugin_invoke_failure(
                state,
                &manifest.plugin_id,
                current_time_ms(),
                Some(EXT_PLUGIN_EXEC_FAILED.to_string()),
                Some(message.clone()),
                breaker_limit,
            );
            return Err(PluginInvokeError {
                code: EXT_PLUGIN_EXEC_FAILED.to_string(),
                message,
                duration_ms: started.elapsed().as_millis() as u64,
                breaker_open: tripped,
            });
        };
        tokio::time::timeout(
            Duration::from_millis(timeout_ms),
            stdout.read_line(&mut line),
        )
        .await
    };
    let bytes = match read_result {
        Ok(Ok(bytes)) => bytes,
        Ok(Err(err)) => {
            guard.stop().await;
            let message = format!("plugin daemon stdout read failed: {err}");
            let tripped = record_plugin_invoke_failure(
                state,
                &manifest.plugin_id,
                current_time_ms(),
                Some(EXT_PLUGIN_EXEC_FAILED.to_string()),
                Some(message.clone()),
                breaker_limit,
            );
            return Err(PluginInvokeError {
                code: EXT_PLUGIN_EXEC_FAILED.to_string(),
                message,
                duration_ms: started.elapsed().as_millis() as u64,
                breaker_open: tripped,
            });
        }
        Err(_) => {
            guard.stop().await;
            let message = format!(
                "plugin daemon timed out after {}ms for '{}'",
                timeout_ms, manifest.plugin_id
            );
            let tripped = record_plugin_invoke_failure(
                state,
                &manifest.plugin_id,
                current_time_ms(),
                Some(EXT_PLUGIN_TIMEOUT.to_string()),
                Some(message.clone()),
                breaker_limit,
            );
            return Err(PluginInvokeError {
                code: EXT_PLUGIN_TIMEOUT.to_string(),
                message,
                duration_ms: started.elapsed().as_millis() as u64,
                breaker_open: tripped,
            });
        }
    };
    if bytes == 0 {
        guard.stop().await;
        let message = "plugin daemon returned EOF".to_string();
        let tripped = record_plugin_invoke_failure(
            state,
            &manifest.plugin_id,
            current_time_ms(),
            Some(EXT_PLUGIN_EXEC_FAILED.to_string()),
            Some(message.clone()),
            breaker_limit,
        );
        return Err(PluginInvokeError {
            code: EXT_PLUGIN_EXEC_FAILED.to_string(),
            message,
            duration_ms: started.elapsed().as_millis() as u64,
            breaker_open: tripped,
        });
    }
    drop(guard);

    if line.chars().count() > max_output_chars {
        let message = format!(
            "plugin daemon output exceeded {} chars for '{}'",
            max_output_chars, manifest.plugin_id
        );
        let tripped = record_plugin_invoke_failure(
            state,
            &manifest.plugin_id,
            current_time_ms(),
            Some(EXT_PLUGIN_OUTPUT_INVALID.to_string()),
            Some(message.clone()),
            breaker_limit,
        );
        return Err(PluginInvokeError {
            code: EXT_PLUGIN_OUTPUT_INVALID.to_string(),
            message,
            duration_ms: started.elapsed().as_millis() as u64,
            breaker_open: tripped,
        });
    }

    let parsed = match parse_plugin_runner_response_strict(&line) {
        Ok(parsed) => parsed,
        Err(err) => {
            let message = format!("{}: {}", EXT_PLUGIN_OUTPUT_INVALID, err);
            let tripped = record_plugin_invoke_failure(
                state,
                &manifest.plugin_id,
                current_time_ms(),
                Some(EXT_PLUGIN_OUTPUT_INVALID.to_string()),
                Some(message.clone()),
                breaker_limit,
            );
            return Err(PluginInvokeError {
                code: EXT_PLUGIN_OUTPUT_INVALID.to_string(),
                message,
                duration_ms: started.elapsed().as_millis() as u64,
                breaker_open: tripped,
            });
        }
    };
    if parsed.request_id != request_id {
        let message = format!(
            "plugin daemon response request_id mismatch: expected {}, got {}",
            request_id, parsed.request_id
        );
        let tripped = record_plugin_invoke_failure(
            state,
            &manifest.plugin_id,
            current_time_ms(),
            Some(EXT_PLUGIN_SCHEMA_INVALID.to_string()),
            Some(message.clone()),
            breaker_limit,
        );
        return Err(PluginInvokeError {
            code: EXT_PLUGIN_SCHEMA_INVALID.to_string(),
            message,
            duration_ms: started.elapsed().as_millis() as u64,
            breaker_open: tripped,
        });
    }

    let duration_ms = started.elapsed().as_millis() as u64;
    let output_chars = line.chars().count();
    if parsed.status == "error" {
        let code = parsed
            .error_code
            .clone()
            .filter(|value| !value.trim().is_empty())
            .unwrap_or_else(|| EXT_PLUGIN_EXEC_FAILED.to_string());
        let message = parsed
            .error_message
            .clone()
            .filter(|value| !value.trim().is_empty())
            .unwrap_or_else(|| "plugin daemon returned status=error".to_string());
        let tripped = record_plugin_invoke_failure(
            state,
            &manifest.plugin_id,
            current_time_ms(),
            Some(code.clone()),
            Some(message.clone()),
            breaker_limit,
        );
        return Err(PluginInvokeError {
            code,
            message,
            duration_ms,
            breaker_open: tripped,
        });
    }

    record_plugin_invoke_success(state, &manifest.plugin_id, current_time_ms());
    Ok(PluginInvokeResult {
        status: parsed.status,
        result: parsed.result,
        error_code: parsed.error_code,
        error_message: parsed.error_message,
        duration_ms,
        output_chars,
    })
}

async fn invoke_plugin_runner(
    state: &AppState,
    manifest: &CorePluginManifest,
    kind: &str,
    payload: serde_json::Value,
) -> std::result::Result<PluginInvokeResult, PluginInvokeError> {
    match manifest.artifact.exec_kind {
        CorePluginExecKind::Subprocess => {
            invoke_plugin_runner_subprocess_impl(state, manifest, kind, payload).await
        }
        CorePluginExecKind::Daemon => {
            invoke_plugin_runner_daemon(state, manifest, kind, payload).await
        }
    }
}

async fn invoke_plugin_hooks_for_point(
    state: &AppState,
    run: &RunRecord,
    hook_point: HookPoint,
    tool_name: Option<&str>,
    metadata: &serde_json::Value,
) -> Vec<PluginHookInvocationOutcome> {
    let runtime_config = match load_runtime_config(state) {
        Ok(config) => config,
        Err(err) => {
            warn!(
                run_id = %run.run_id,
                hook_point = %hook_point.as_str(),
                error = %err,
                "failed loading runtime config before plugin hook invocation"
            );
            return Vec::new();
        }
    };

    let hook_name = hook_point_capability_name(hook_point);
    let manifests = state.plugin_registry.read().await.list_manifests();
    let mut outcomes = Vec::new();
    for manifest in manifests {
        if !manifest.enabled {
            continue;
        }
        if !manifest
            .capabilities
            .hooks
            .iter()
            .any(|capability| capability.name.trim() == hook_name)
        {
            continue;
        }
        if manifest.schema_version.trim() != PLUGIN_MANIFEST_SCHEMA_VERSION_V2 {
            continue;
        }
        if manifest.artifact.command.trim().is_empty() {
            continue;
        }
        if !state.extension_policy.plugin_allowed(&manifest.plugin_id) {
            continue;
        }
        if let Err(err) = ensure_daemon_allowlist(&runtime_config, &manifest) {
            outcomes.push(PluginHookInvocationOutcome {
                plugin_id: manifest.plugin_id,
                hook_name: hook_name.to_string(),
                status: "deny".to_string(),
                error_code: Some(EXT_PLUGIN_DAEMON_NOT_ALLOWLISTED.to_string()),
                error: Some(err.to_string()),
                duration_ms: 0,
                breaker_open: false,
            });
            continue;
        }

        let payload = serde_json::json!({
            "hook_name": hook_name,
            "hook_point": hook_point.as_str(),
            "run_id": run.run_id,
            "session_id": run.session_id,
            "tool_name": tool_name,
            "metadata": metadata
        });
        emit_event(
            state,
            "extension.plugin.invoked",
            serde_json::json!({
                "plugin_id": manifest.plugin_id,
                "hook_name": hook_name,
                "run_id": run.run_id,
                "session_id": run.session_id,
                "transport": "subprocess",
                "exec_kind": match manifest.artifact.exec_kind {
                    CorePluginExecKind::Subprocess => "subprocess",
                    CorePluginExecKind::Daemon => "daemon",
                }
            }),
        );
        match invoke_plugin_runner(state, &manifest, "hook", payload).await {
            Ok(result) => {
                emit_event(
                    state,
                    "extension.plugin.succeeded",
                    serde_json::json!({
                        "plugin_id": manifest.plugin_id,
                        "hook_name": hook_name,
                        "run_id": run.run_id,
                        "status": result.status,
                        "duration_ms": result.duration_ms,
                        "output_chars": result.output_chars
                    }),
                );
                outcomes.push(PluginHookInvocationOutcome {
                    plugin_id: manifest.plugin_id,
                    hook_name: hook_name.to_string(),
                    status: result.status,
                    error_code: result.error_code,
                    error: result.error_message,
                    duration_ms: result.duration_ms,
                    breaker_open: false,
                });
            }
            Err(err) => {
                emit_event(
                    state,
                    "extension.plugin.failed",
                    serde_json::json!({
                        "plugin_id": manifest.plugin_id,
                        "hook_name": hook_name,
                        "run_id": run.run_id,
                        "error_code": err.code,
                        "error": err.message,
                        "duration_ms": err.duration_ms
                    }),
                );
                if err.breaker_open {
                    reset_plugin_daemon_supervisor(state, &manifest.plugin_id).await;
                    emit_event(
                        state,
                        "extension.plugin.disabled",
                        serde_json::json!({
                            "plugin_id": manifest.plugin_id,
                            "hook_name": hook_name,
                            "run_id": run.run_id,
                            "error_code": err.code
                        }),
                    );
                }
                outcomes.push(PluginHookInvocationOutcome {
                    plugin_id: manifest.plugin_id,
                    hook_name: hook_name.to_string(),
                    status: "error".to_string(),
                    error_code: Some(err.code),
                    error: Some(err.message),
                    duration_ms: err.duration_ms,
                    breaker_open: err.breaker_open,
                });
            }
        }
    }
    outcomes
}

async fn refresh_plugin_hook_runtime(
    state: &AppState,
    plugin_registry_snapshot: &PluginRegistry,
) -> AnyResult<usize> {
    let (new_hook_bus, denials) =
        build_hook_bus_from_registry(plugin_registry_snapshot, state.extension_policy.as_ref())?;
    state
        .hook_bus
        .replace_with(&new_hook_bus)
        .context("failed replacing extension hook registry")?;
    record_extension_hook_policy_denials(state, &denials);
    Ok(denials.len())
}

async fn install_plugin(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(request): Json<InstallPluginRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let mut manifest = parse_plugin_manifest_request(request.manifest)
        .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
    if manifest.schema_version.trim() != PLUGIN_MANIFEST_SCHEMA_VERSION_V2 {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "plugin install requires schema_version carsinos.plugin.manifest.v2",
        ));
    }
    let plugin_id = normalize_plugin_id(&manifest.plugin_id)
        .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    let resource = format!("plugin:{plugin_id}");
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN],
        "extension.plugin.install",
        &resource,
    )?;
    if !state.extension_policy.plugin_allowed(&plugin_id) {
        return Err(api_error_with_code(
            StatusCode::FORBIDDEN,
            "POLICY_DENY",
            "plugin is not allowlisted by extension policy",
        ));
    }
    manifest.plugin_id = plugin_id.clone();
    let runtime_config = load_runtime_config(&state)
        .map_err(|err| internal_err_with_error("loading runtime config failed", err))?;
    let plugin_storage_root = plugin_storage_root_from_runtime(&state, &runtime_config)
        .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;

    ensure_plugin_tool_names_do_not_collide(&manifest).map_err(|err| {
        api_error_with_code(
            StatusCode::BAD_REQUEST,
            EXT_PLUGIN_TOOL_NAME_COLLISION,
            &err.to_string(),
        )
    })?;
    ensure_daemon_allowlist(&runtime_config, &manifest).map_err(|err| {
        api_error_with_code(
            StatusCode::BAD_REQUEST,
            EXT_PLUGIN_DAEMON_NOT_ALLOWLISTED,
            &err.to_string(),
        )
    })?;

    let (installed_manifest, plugin_registry_snapshot, active_manifest_path, pointer_path) = {
        let mut registry = state.plugin_registry.write().await;
        if registry.get_manifest(&plugin_id).is_some() {
            return Err(api_error(
                StatusCode::BAD_REQUEST,
                "plugin_id already exists; use update endpoint",
            ));
        }

        let mut candidate = registry.clone();
        candidate
            .register_manifest(manifest)
            .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
        let normalized = candidate.get_manifest(&plugin_id).ok_or_else(|| {
            api_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "plugin manifest missing after install validation",
            )
        })?;
        let materialized = materialize_plugin_bundle(&plugin_storage_root, &normalized)
            .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
        candidate
            .replace_manifest(materialized)
            .map_err(|err| internal_err_with_error("materializing plugin manifest failed", err))?;
        let installed = candidate.get_manifest(&plugin_id).ok_or_else(|| {
            api_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "plugin manifest missing after install",
            )
        })?;
        let active_path = plugin_active_manifest_path(&plugin_storage_root, &plugin_id);
        persist_plugin_manifest(&active_path, &installed).map_err(|err| {
            internal_err_with_error("persisting active plugin manifest failed", err)
        })?;
        let pointer_path = plugin_pointer_path(&plugin_storage_root, &plugin_id);
        let pointer = PluginVersionPointersRecord {
            schema_version: PLUGIN_POINTER_SCHEMA_VERSION.to_string(),
            plugin_id: plugin_id.clone(),
            active_version: installed.plugin_version.clone(),
            previous_version: None,
            updated_at: current_time_ms(),
        };
        persist_plugin_pointer(&pointer_path, &pointer)
            .map_err(|err| internal_err_with_error("persisting plugin pointer failed", err))?;
        *registry = candidate;
        (installed, registry.clone(), active_path, pointer_path)
    };
    reset_plugin_daemon_supervisor(&state, &plugin_id).await;
    let hook_policy_denials = refresh_plugin_hook_runtime(&state, &plugin_registry_snapshot)
        .await
        .map_err(|err| internal_err_with_error("refreshing plugin hook runtime failed", err))?;
    let reason = request
        .reason
        .as_ref()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    record_security_audit(
        &headers,
        &state,
        &auth,
        "extension.plugin.install",
        &resource,
        "allow",
        reason.clone(),
        StatusCode::OK,
        None,
        None,
        None,
        Some(serde_json::json!({
            "plugin_id": plugin_id,
            "plugin_version": installed_manifest.plugin_version,
            "plugin_storage_root": plugin_storage_root.display().to_string(),
            "active_manifest_path": active_manifest_path.display().to_string(),
            "pointer_path": pointer_path.display().to_string(),
            "hook_policy_denials": hook_policy_denials,
            "reason": reason
        })),
    );
    Ok(Json(InstallPluginResponse {
        plugin: to_plugin_manifest_response(installed_manifest),
        rollback_available: false,
        hook_policy_denials,
    }))
}

async fn update_plugin(
    headers: HeaderMap,
    State(state): State<AppState>,
    Path(plugin_id): Path<String>,
    Json(request): Json<UpdatePluginRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let plugin_id = normalize_plugin_id(&plugin_id)
        .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
    let mut manifest = parse_plugin_manifest_request(request.manifest)
        .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
    if manifest.schema_version.trim() != PLUGIN_MANIFEST_SCHEMA_VERSION_V2 {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "plugin update requires schema_version carsinos.plugin.manifest.v2",
        ));
    }
    let manifest_plugin_id = normalize_plugin_id(&manifest.plugin_id)
        .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
    if manifest_plugin_id != plugin_id {
        return Err(api_error(
            StatusCode::BAD_REQUEST,
            "manifest plugin_id must match path plugin_id",
        ));
    }

    let auth = require_bearer_auth_with_error(&headers, &state)?;
    let resource = format!("plugin:{plugin_id}");
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN],
        "extension.plugin.update",
        &resource,
    )?;
    if !state.extension_policy.plugin_allowed(&plugin_id) {
        return Err(api_error_with_code(
            StatusCode::FORBIDDEN,
            "POLICY_DENY",
            "plugin is not allowlisted by extension policy",
        ));
    }
    manifest.plugin_id = plugin_id.clone();
    let runtime_config = load_runtime_config(&state)
        .map_err(|err| internal_err_with_error("loading runtime config failed", err))?;
    let plugin_storage_root = plugin_storage_root_from_runtime(&state, &runtime_config)
        .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
    ensure_plugin_tool_names_do_not_collide(&manifest).map_err(|err| {
        api_error_with_code(
            StatusCode::BAD_REQUEST,
            EXT_PLUGIN_TOOL_NAME_COLLISION,
            &err.to_string(),
        )
    })?;
    ensure_daemon_allowlist(&runtime_config, &manifest).map_err(|err| {
        api_error_with_code(
            StatusCode::BAD_REQUEST,
            EXT_PLUGIN_DAEMON_NOT_ALLOWLISTED,
            &err.to_string(),
        )
    })?;

    let (
        updated_manifest,
        previous_manifest,
        plugin_registry_snapshot,
        active_manifest_path,
        pointer_path,
    ) = {
        let mut registry = state.plugin_registry.write().await;
        let mut candidate = registry.clone();
        let previous = candidate
            .get_manifest(&plugin_id)
            .ok_or_else(|| api_error(StatusCode::NOT_FOUND, "plugin_id not found"))?;
        candidate
            .replace_manifest(manifest)
            .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
        let normalized = candidate.get_manifest(&plugin_id).ok_or_else(|| {
            api_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "plugin manifest missing after update validation",
            )
        })?;
        ensure_plugin_tool_names_do_not_collide(&normalized).map_err(|err| {
            api_error_with_code(
                StatusCode::BAD_REQUEST,
                EXT_PLUGIN_TOOL_NAME_COLLISION,
                &err.to_string(),
            )
        })?;
        ensure_daemon_allowlist(&runtime_config, &normalized).map_err(|err| {
            api_error_with_code(
                StatusCode::BAD_REQUEST,
                EXT_PLUGIN_DAEMON_NOT_ALLOWLISTED,
                &err.to_string(),
            )
        })?;
        let materialized = materialize_plugin_bundle(&plugin_storage_root, &normalized)
            .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
        let updated = candidate
            .replace_manifest(materialized)
            .map_err(|err| internal_err_with_error("materializing plugin manifest failed", err))?;
        let active_path = plugin_active_manifest_path(&plugin_storage_root, &plugin_id);
        persist_plugin_manifest(&active_path, &updated).map_err(|err| {
            internal_err_with_error("persisting active plugin manifest failed", err)
        })?;
        let pointer_path = plugin_pointer_path(&plugin_storage_root, &plugin_id);
        let pointer = PluginVersionPointersRecord {
            schema_version: PLUGIN_POINTER_SCHEMA_VERSION.to_string(),
            plugin_id: plugin_id.clone(),
            active_version: updated.plugin_version.clone(),
            previous_version: Some(previous.plugin_version.clone()),
            updated_at: current_time_ms(),
        };
        persist_plugin_pointer(&pointer_path, &pointer)
            .map_err(|err| internal_err_with_error("persisting plugin pointer failed", err))?;
        *registry = candidate;
        (
            updated,
            previous,
            registry.clone(),
            active_path,
            pointer_path,
        )
    };
    reset_plugin_daemon_supervisor(&state, &plugin_id).await;
    let hook_policy_denials = refresh_plugin_hook_runtime(&state, &plugin_registry_snapshot)
        .await
        .map_err(|err| internal_err_with_error("refreshing plugin hook runtime failed", err))?;
    let reason = request
        .reason
        .as_ref()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    record_security_audit(
        &headers,
        &state,
        &auth,
        "extension.plugin.update",
        &resource,
        "allow",
        reason.clone(),
        StatusCode::OK,
        None,
        None,
        None,
        Some(serde_json::json!({
            "plugin_id": plugin_id,
            "previous_version": previous_manifest.plugin_version,
            "plugin_version": updated_manifest.plugin_version,
            "plugin_storage_root": plugin_storage_root.display().to_string(),
            "active_manifest_path": active_manifest_path.display().to_string(),
            "pointer_path": pointer_path.display().to_string(),
            "hook_policy_denials": hook_policy_denials,
            "reason": reason
        })),
    );
    Ok(Json(UpdatePluginResponse {
        plugin: to_plugin_manifest_response(updated_manifest),
        rollback_available: true,
        hook_policy_denials,
    }))
}

async fn rollback_plugin(
    headers: HeaderMap,
    State(state): State<AppState>,
    Path(plugin_id): Path<String>,
    Json(request): Json<RollbackPluginRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let plugin_id = normalize_plugin_id(&plugin_id)
        .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    let resource = format!("plugin:{plugin_id}");
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN],
        "extension.plugin.rollback",
        &resource,
    )?;

    let runtime_config = load_runtime_config(&state)
        .map_err(|err| internal_err_with_error("loading runtime config failed", err))?;
    let plugin_storage_root = plugin_storage_root_from_runtime(&state, &runtime_config)
        .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
    let pointer_path = plugin_pointer_path(&plugin_storage_root, &plugin_id);
    let pointer = load_plugin_pointer(&pointer_path)
        .map_err(|err| internal_err_with_error("loading plugin pointer failed", err))?
        .ok_or_else(|| {
            api_error(
                StatusCode::BAD_REQUEST,
                "plugin rollback pointer is missing",
            )
        })?;
    let rollback_version = pointer
        .previous_version
        .clone()
        .ok_or_else(|| api_error(StatusCode::BAD_REQUEST, "plugin rollback target is missing"))?;
    let rollback_manifest =
        load_bundle_manifest(&plugin_storage_root, &plugin_id, &rollback_version).map_err(
            |err| internal_err_with_error("loading rollback bundle manifest failed", err),
        )?;
    ensure_plugin_tool_names_do_not_collide(&rollback_manifest).map_err(|err| {
        api_error_with_code(
            StatusCode::BAD_REQUEST,
            EXT_PLUGIN_TOOL_NAME_COLLISION,
            &err.to_string(),
        )
    })?;
    ensure_daemon_allowlist(&runtime_config, &rollback_manifest).map_err(|err| {
        api_error_with_code(
            StatusCode::BAD_REQUEST,
            EXT_PLUGIN_DAEMON_NOT_ALLOWLISTED,
            &err.to_string(),
        )
    })?;

    let (current_manifest, rolled_back_manifest, plugin_registry_snapshot, active_manifest_path) = {
        let mut registry = state.plugin_registry.write().await;
        let mut candidate = registry.clone();
        let current = candidate
            .get_manifest(&plugin_id)
            .ok_or_else(|| api_error(StatusCode::NOT_FOUND, "plugin_id not found"))?;
        let rolled_back = candidate
            .replace_manifest(rollback_manifest)
            .map_err(|err| api_error(StatusCode::BAD_REQUEST, &err.to_string()))?;
        let active_path = plugin_active_manifest_path(&plugin_storage_root, &plugin_id);
        persist_plugin_manifest(&active_path, &rolled_back).map_err(|err| {
            internal_err_with_error("persisting active plugin manifest failed", err)
        })?;
        let next_pointer = PluginVersionPointersRecord {
            schema_version: PLUGIN_POINTER_SCHEMA_VERSION.to_string(),
            plugin_id: plugin_id.clone(),
            active_version: rolled_back.plugin_version.clone(),
            previous_version: Some(current.plugin_version.clone()),
            updated_at: current_time_ms(),
        };
        persist_plugin_pointer(&pointer_path, &next_pointer)
            .map_err(|err| internal_err_with_error("persisting plugin pointer failed", err))?;
        *registry = candidate;
        (current, rolled_back, registry.clone(), active_path)
    };
    reset_plugin_daemon_supervisor(&state, &plugin_id).await;
    let hook_policy_denials = refresh_plugin_hook_runtime(&state, &plugin_registry_snapshot)
        .await
        .map_err(|err| internal_err_with_error("refreshing plugin hook runtime failed", err))?;
    let reason = request
        .reason
        .as_ref()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    record_security_audit(
        &headers,
        &state,
        &auth,
        "extension.plugin.rollback",
        &resource,
        "allow",
        reason.clone(),
        StatusCode::OK,
        None,
        None,
        None,
        Some(serde_json::json!({
            "plugin_id": plugin_id,
            "restored_version": rolled_back_manifest.plugin_version,
            "next_rollback_version": current_manifest.plugin_version,
            "rollback_from_version": rollback_version,
            "plugin_storage_root": plugin_storage_root.display().to_string(),
            "active_manifest_path": active_manifest_path.display().to_string(),
            "pointer_path": pointer_path.display().to_string(),
            "hook_policy_denials": hook_policy_denials,
            "reason": reason
        })),
    );
    Ok(Json(RollbackPluginResponse {
        plugin: to_plugin_manifest_response(rolled_back_manifest),
        rollback_available: true,
        hook_policy_denials,
    }))
}

async fn list_skills(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<ListSkillsQuery>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN, ROLE_OPERATOR_READONLY],
        "skill.registry.list",
        "skills",
    )?;

    let include_disabled = query.include_disabled.unwrap_or(false);
    let mut skills = state.skill_registry.read().await.list();
    if !include_disabled {
        skills.retain(|skill| skill.enabled);
    }
    let items = skills
        .into_iter()
        .map(to_skill_response)
        .collect::<Vec<_>>();
    Ok(Json(ListSkillsResponse {
        contract_version: SKILL_REGISTRY_CONTRACT_VERSION.to_string(),
        items,
    }))
}

async fn update_skill_state(
    headers: HeaderMap,
    State(state): State<AppState>,
    Path(skill_id): Path<String>,
    Json(request): Json<UpdateSkillStateRequest>,
) -> std::result::Result<impl IntoResponse, (StatusCode, Json<ApiError>)> {
    let auth = require_bearer_auth_with_error(&headers, &state)?;
    let resource = format!("skill:{skill_id}");
    require_roles_with_audit(
        &headers,
        &state,
        &auth,
        &[ROLE_OPERATOR_ADMIN],
        "skill.state.update",
        &resource,
    )?;
    if state.extension_policy.skill_is_reserved(&skill_id) {
        let reason = format!(
            "skill '{}' is reserved by extension policy",
            skill_id.trim()
        );
        record_security_audit(
            &headers,
            &state,
            &auth,
            "skill.state.update",
            &resource,
            "deny",
            Some(reason.clone()),
            StatusCode::FORBIDDEN,
            Some("POLICY_DENY"),
            None,
            None,
            Some(serde_json::json!({
                "skill_id": skill_id.trim(),
                "requested_enabled": request.enabled,
                "policy": "reserved_skill"
            })),
        );
        return Err(api_error_with_code(
            StatusCode::FORBIDDEN,
            "POLICY_DENY",
            &reason,
        ));
    }

    let (updated, overrides) = {
        let mut registry = state.skill_registry.write().await;
        let updated = registry
            .set_enabled(&skill_id, request.enabled)
            .map_err(|err| api_error(StatusCode::NOT_FOUND, &err.to_string()))?;
        let overrides = skill_state_overrides_from_registry(&registry);
        (updated, overrides)
    };
    let overrides_json = serde_json::to_string(&overrides).map_err(|err| {
        internal_err_with_error("serializing skill state overrides failed", err.into())
    })?;
    state
        .storage
        .set_app_kv_json(APP_KV_SKILLS_STATE, overrides_json)
        .map_err(|err| internal_err_with_error("saving skill state overrides failed", err))?;

    record_security_audit(
        &headers,
        &state,
        &auth,
        "skill.state.update",
        &format!("skill:{}", updated.skill_id),
        "allow",
        Some("skill state updated".to_string()),
        StatusCode::OK,
        None,
        None,
        None,
        Some(serde_json::json!({
            "skill_id": &updated.skill_id,
            "enabled": updated.enabled
        })),
    );

    Ok(Json(UpdateSkillStateResponse {
        skill: to_skill_response(updated),
    }))
}

async fn ws_handler(
    headers: HeaderMap,
    Query(query): Query<WsAuthQuery>,
    ws: WebSocketUpgrade,
    State(state): State<AppState>,
) -> std::result::Result<impl IntoResponse, StatusCode> {
    let auth_headers = ws_auth_headers_with_query_token(&headers, &query)?;
    let auth_ctx = require_bearer_auth(&auth_headers, &state).map_err(|err| err.status)?;
    require_roles_raw(
        &auth_ctx,
        &[
            ROLE_OPERATOR_ADMIN,
            ROLE_OPERATOR_READONLY,
            ROLE_AUTOMATION_RUNNER,
        ],
    )
    .map_err(|err| err.status)?;
    info!("websocket client connected");
    let rx = state.event_tx.subscribe();
    let event_seq = state.event_seq.clone();
    Ok(ws.on_upgrade(move |socket| handle_socket(socket, rx, state.started_at, event_seq)))
}

#[derive(Deserialize, Default)]
struct WsAuthQuery {
    token: Option<String>,
}

fn ws_auth_headers_with_query_token(
    headers: &HeaderMap,
    query: &WsAuthQuery,
) -> std::result::Result<HeaderMap, StatusCode> {
    if headers.contains_key(header::AUTHORIZATION) {
        return Ok(headers.clone());
    }
    let Some(token) = query
        .token
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    else {
        return Ok(headers.clone());
    };
    let mut merged = headers.clone();
    let auth_header =
        HeaderValue::from_str(&format!("Bearer {token}")).map_err(|_| StatusCode::UNAUTHORIZED)?;
    merged.insert(header::AUTHORIZATION, auth_header);
    Ok(merged)
}

async fn handle_socket(
    mut socket: WebSocket,
    mut event_rx: broadcast::Receiver<String>,
    started_at: DateTime<Utc>,
    event_seq: Arc<AtomicU64>,
) {
    let seq = event_seq.fetch_add(1, Ordering::Relaxed);
    let event = WsEventFrame::new(
        seq,
        "gateway.status",
        serde_json::json!({
            "service": "carsinos-gateway",
            "started_at_utc": started_at,
            "now_utc": Utc::now(),
            "status": "ok"
        }),
    );

    let initial_frame = match serde_json::to_string(&event) {
        Ok(frame) => frame,
        Err(err) => {
            warn!(error = %err, "failed to serialize websocket gateway.status frame");
            return;
        }
    };

    if socket
        .send(Message::Text(initial_frame.into()))
        .await
        .is_err()
    {
        debug!("websocket closed before initial status frame");
        return;
    }

    loop {
        tokio::select! {
            incoming = socket.recv() => {
                match incoming {
                    Some(Ok(Message::Text(_))) | Some(Ok(Message::Binary(_))) | Some(Ok(Message::Ping(_))) => {
                        // Keep the connection alive; we don't consume client commands on WS in v1.
                    }
                    Some(Ok(Message::Close(_))) => break,
                    Some(Ok(Message::Pong(_))) => {}
                    Some(Err(_)) | None => break,
                }
            }
            event = event_rx.recv() => {
                match event {
                    Ok(frame) => {
                        if socket.send(Message::Text(frame.into())).await.is_err() {
                            break;
                        }
                    }
                    Err(broadcast::error::RecvError::Lagged(_)) => {
                        continue;
                    }
                    Err(broadcast::error::RecvError::Closed) => break,
                }
            }
        }
    }
    info!("websocket client disconnected");
}

fn require_bearer_auth(
    headers: &HeaderMap,
    state: &AppState,
) -> std::result::Result<AuthContext, AuthError> {
    state.metrics.requests_total.fetch_add(1, Ordering::Relaxed);
    let client_ip = resolve_client_ip(headers, state).inspect_err(|_| {
        state
            .metrics
            .auth_failures_total
            .fetch_add(1, Ordering::Relaxed);
    })?;
    if headers
        .get(INTERNAL_CHANNEL_INGEST_HEADER)
        .and_then(|value| value.to_str().ok())
        .is_some_and(|token| token == state.internal_channel_ingest_token.as_str())
    {
        let mut roles = HashSet::new();
        roles.insert(ROLE_CHANNEL_ADAPTER.to_string());
        roles.insert(ROLE_SERVICE_INTERNAL.to_string());
        let auth_context = AuthContext {
            principal_id: "channel_listener".to_string(),
            roles,
            auth_method: "internal_ingest",
            token_id: None,
            session_id: None,
            client_ip,
        };
        if state.rate_limiter.config.enabled {
            state
                .rate_limiter
                .check(
                    &format!("ip:{}", auth_context.client_ip),
                    state.rate_limiter.config.per_ip_limit,
                )
                .inspect_err(|_| {
                    state
                        .metrics
                        .auth_failures_total
                        .fetch_add(1, Ordering::Relaxed);
                })?;
            state
                .rate_limiter
                .check(
                    &format!("principal:{}", auth_context.principal_id),
                    state.rate_limiter.config.per_principal_limit,
                )
                .inspect_err(|_| {
                    state
                        .metrics
                        .auth_failures_total
                        .fetch_add(1, Ordering::Relaxed);
                })?;
        }
        return Ok(auth_context);
    }
    let token = parse_bearer_token(headers).ok_or_else(|| {
        state
            .metrics
            .auth_failures_total
            .fetch_add(1, Ordering::Relaxed);
        warn!("auth rejected: missing bearer token");
        AuthError {
            status: StatusCode::UNAUTHORIZED,
            code: "AUTH_REQUIRED",
            message: "missing bearer token".to_string(),
            retry_after_seconds: None,
        }
    })?;

    let auth_context = match state.auth_mode {
        AuthMode::StaticBearer => {
            if token != state.auth_token.as_str() {
                state
                    .metrics
                    .auth_failures_total
                    .fetch_add(1, Ordering::Relaxed);
                warn!("auth rejected: static bearer token mismatch");
                return Err(AuthError {
                    status: StatusCode::UNAUTHORIZED,
                    code: "AUTH_INVALID",
                    message: "invalid bearer token".to_string(),
                    retry_after_seconds: None,
                });
            }
            let mut roles = HashSet::new();
            roles.insert(ROLE_OPERATOR_ADMIN.to_string());
            roles.insert(ROLE_OPERATOR_READONLY.to_string());
            roles.insert(ROLE_AUTOMATION_RUNNER.to_string());
            roles.insert(ROLE_CHANNEL_ADAPTER.to_string());
            roles.insert(ROLE_SERVICE_INTERNAL.to_string());
            AuthContext {
                principal_id: "static_bearer".to_string(),
                roles,
                auth_method: "static_bearer",
                token_id: None,
                session_id: None,
                client_ip,
            }
        }
        AuthMode::Jwt => authenticate_jwt(token, state, client_ip)?,
    };

    if state.rate_limiter.config.enabled {
        state
            .rate_limiter
            .check(
                &format!("ip:{}", auth_context.client_ip),
                state.rate_limiter.config.per_ip_limit,
            )
            .inspect_err(|_| {
                state
                    .metrics
                    .auth_failures_total
                    .fetch_add(1, Ordering::Relaxed);
            })?;
        state
            .rate_limiter
            .check(
                &format!("principal:{}", auth_context.principal_id),
                state.rate_limiter.config.per_principal_limit,
            )
            .inspect_err(|_| {
                state
                    .metrics
                    .auth_failures_total
                    .fetch_add(1, Ordering::Relaxed);
            })?;
    }

    Ok(auth_context)
}

fn authenticate_jwt(
    token: &str,
    state: &AppState,
    client_ip: String,
) -> std::result::Result<AuthContext, AuthError> {
    let jwt = state.jwt_auth.as_ref().ok_or_else(|| AuthError {
        status: StatusCode::INTERNAL_SERVER_ERROR,
        code: "INTERNAL_ERROR",
        message: "jwt mode configured without jwt settings".to_string(),
        retry_after_seconds: None,
    })?;

    let mut validation = Validation::new(Algorithm::HS256);
    validation.validate_exp = false;
    validation.validate_aud = false;
    validation.required_spec_claims = HashSet::new();
    let token_data = jsonwebtoken::decode::<JwtClaims>(
        token,
        &DecodingKey::from_secret(jwt.secret.as_bytes()),
        &validation,
    )
    .map_err(|err| {
        state
            .metrics
            .auth_failures_total
            .fetch_add(1, Ordering::Relaxed);
        let code = match err.kind() {
            jsonwebtoken::errors::ErrorKind::ExpiredSignature => "AUTH_EXPIRED",
            _ => "AUTH_INVALID",
        };
        AuthError {
            status: StatusCode::UNAUTHORIZED,
            code,
            message: "invalid jwt token".to_string(),
            retry_after_seconds: None,
        }
    })?;

    let claims = token_data.claims;
    let now = Utc::now().timestamp();
    let skew = jwt.clock_skew_seconds.max(0);
    if claims.iss.trim() != jwt.issuer {
        state
            .metrics
            .auth_failures_total
            .fetch_add(1, Ordering::Relaxed);
        return Err(AuthError {
            status: StatusCode::UNAUTHORIZED,
            code: "AUTH_INVALID",
            message: "jwt issuer mismatch".to_string(),
            retry_after_seconds: None,
        });
    }
    if !audience_matches(&claims.aud, &jwt.audience) {
        state
            .metrics
            .auth_failures_total
            .fetch_add(1, Ordering::Relaxed);
        return Err(AuthError {
            status: StatusCode::UNAUTHORIZED,
            code: "AUTH_INVALID",
            message: "jwt audience mismatch".to_string(),
            retry_after_seconds: None,
        });
    }
    if now > claims.exp.saturating_add(skew) {
        state
            .metrics
            .auth_failures_total
            .fetch_add(1, Ordering::Relaxed);
        return Err(AuthError {
            status: StatusCode::UNAUTHORIZED,
            code: "AUTH_EXPIRED",
            message: "jwt token expired".to_string(),
            retry_after_seconds: None,
        });
    }
    if claims.iat > now.saturating_add(skew) {
        state
            .metrics
            .auth_failures_total
            .fetch_add(1, Ordering::Relaxed);
        return Err(AuthError {
            status: StatusCode::UNAUTHORIZED,
            code: "AUTH_INVALID",
            message: "jwt issued-at claim is in the future".to_string(),
            retry_after_seconds: None,
        });
    }
    if now.saturating_sub(claims.iat).saturating_sub(skew) > jwt.max_token_age_seconds {
        state
            .metrics
            .auth_failures_total
            .fetch_add(1, Ordering::Relaxed);
        return Err(AuthError {
            status: StatusCode::UNAUTHORIZED,
            code: "AUTH_EXPIRED",
            message: "jwt token age exceeds maximum".to_string(),
            retry_after_seconds: None,
        });
    }
    if claims.sub.trim().is_empty() {
        state
            .metrics
            .auth_failures_total
            .fetch_add(1, Ordering::Relaxed);
        return Err(AuthError {
            status: StatusCode::UNAUTHORIZED,
            code: "AUTH_INVALID",
            message: "jwt subject claim missing".to_string(),
            retry_after_seconds: None,
        });
    }
    if claims.jti.trim().is_empty() {
        state
            .metrics
            .auth_failures_total
            .fetch_add(1, Ordering::Relaxed);
        return Err(AuthError {
            status: StatusCode::UNAUTHORIZED,
            code: "AUTH_INVALID",
            message: "jwt jti claim missing".to_string(),
            retry_after_seconds: None,
        });
    }
    if jwt.revoked_jti.contains(claims.jti.trim()) {
        state
            .metrics
            .auth_failures_total
            .fetch_add(1, Ordering::Relaxed);
        return Err(AuthError {
            status: StatusCode::FORBIDDEN,
            code: "AUTH_FORBIDDEN",
            message: "jwt token id is revoked".to_string(),
            retry_after_seconds: None,
        });
    }
    if jwt.replay_protection_enabled {
        enforce_jwt_replay_protection(
            &state.jwt_replay_jti,
            claims.jti.trim(),
            claims.exp.saturating_add(skew),
            now,
        )
        .inspect_err(|_| {
            state
                .metrics
                .auth_failures_total
                .fetch_add(1, Ordering::Relaxed);
        })?;
    }

    let roles = normalize_roles(&claims.roles).inspect_err(|_| {
        state
            .metrics
            .auth_failures_total
            .fetch_add(1, Ordering::Relaxed);
    })?;
    let _ = claims.scope.as_deref();

    Ok(AuthContext {
        principal_id: claims.sub.trim().to_string(),
        roles,
        auth_method: "jwt",
        token_id: Some(claims.jti.trim().to_string()),
        session_id: claims
            .session_id
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty()),
        client_ip,
    })
}

fn enforce_jwt_replay_protection(
    seen_jti: &StdRwLock<HashMap<String, i64>>,
    token_id: &str,
    expires_at: i64,
    now: i64,
) -> std::result::Result<(), AuthError> {
    let mut guard = seen_jti.write().map_err(|_| AuthError {
        status: StatusCode::INTERNAL_SERVER_ERROR,
        code: "INTERNAL_ERROR",
        message: "jwt replay lock poisoned".to_string(),
        retry_after_seconds: None,
    })?;
    guard.retain(|_, expiry| *expiry > now);
    if guard.get(token_id).is_some_and(|expiry| *expiry > now) {
        return Err(AuthError {
            status: StatusCode::FORBIDDEN,
            code: "AUTH_FORBIDDEN",
            message: "jwt token id replay detected".to_string(),
            retry_after_seconds: None,
        });
    }
    guard.insert(token_id.to_string(), expires_at.max(now.saturating_add(1)));
    Ok(())
}

fn audience_matches(aud_claim: &serde_json::Value, expected: &str) -> bool {
    match aud_claim {
        serde_json::Value::String(value) => value.trim() == expected,
        serde_json::Value::Array(values) => values
            .iter()
            .filter_map(|value| value.as_str())
            .any(|value| value.trim() == expected),
        _ => false,
    }
}

fn normalize_roles(raw_roles: &[String]) -> std::result::Result<HashSet<String>, AuthError> {
    if raw_roles.is_empty() {
        return Err(AuthError {
            status: StatusCode::FORBIDDEN,
            code: "AUTH_ROLE_MISMATCH",
            message: "jwt roles claim is required".to_string(),
            retry_after_seconds: None,
        });
    }
    let mut normalized = HashSet::new();
    for role in raw_roles {
        let value = role.trim().to_string();
        if value.is_empty() {
            continue;
        }
        if !matches!(
            value.as_str(),
            ROLE_OPERATOR_ADMIN
                | ROLE_OPERATOR_READONLY
                | ROLE_AUTOMATION_RUNNER
                | ROLE_CHANNEL_ADAPTER
                | ROLE_SERVICE_INTERNAL
        ) {
            return Err(AuthError {
                status: StatusCode::FORBIDDEN,
                code: "AUTH_ROLE_MISMATCH",
                message: format!("unsupported role claim: {value}"),
                retry_after_seconds: None,
            });
        }
        normalized.insert(value);
    }
    if normalized.is_empty() {
        return Err(AuthError {
            status: StatusCode::FORBIDDEN,
            code: "AUTH_ROLE_MISMATCH",
            message: "jwt roles claim is required".to_string(),
            retry_after_seconds: None,
        });
    }
    Ok(normalized)
}

fn resolve_client_ip(
    headers: &HeaderMap,
    state: &AppState,
) -> std::result::Result<String, AuthError> {
    let fwd = headers
        .get("x-forwarded-for")
        .and_then(|value| value.to_str().ok())
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());

    if state.trusted_proxy_headers {
        let proxy_id = headers
            .get("x-trusted-proxy-id")
            .and_then(|value| value.to_str().ok())
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
            .ok_or_else(|| AuthError {
                status: StatusCode::FORBIDDEN,
                code: "POLICY_DENY",
                message: "trusted proxy id header is required when proxy headers are enabled"
                    .to_string(),
                retry_after_seconds: None,
            })?;
        if !state.trusted_proxy_allowlist.contains(&proxy_id) {
            return Err(AuthError {
                status: StatusCode::FORBIDDEN,
                code: "POLICY_DENY",
                message: "untrusted proxy id".to_string(),
                retry_after_seconds: None,
            });
        }
        let forwarded_for = fwd.ok_or_else(|| AuthError {
            status: StatusCode::FORBIDDEN,
            code: "POLICY_DENY",
            message: "x-forwarded-for is required when proxy headers are enabled".to_string(),
            retry_after_seconds: None,
        })?;
        let first = forwarded_for.split(',').next().unwrap_or_default().trim();
        let ip = first.parse::<IpAddr>().map_err(|_| AuthError {
            status: StatusCode::FORBIDDEN,
            code: "POLICY_DENY",
            message: "invalid x-forwarded-for client ip".to_string(),
            retry_after_seconds: None,
        })?;
        return Ok(ip.to_string());
    }

    if fwd.is_some() {
        return Err(AuthError {
            status: StatusCode::FORBIDDEN,
            code: "POLICY_DENY",
            message: "x-forwarded-for is not accepted when trusted proxy headers are disabled"
                .to_string(),
            retry_after_seconds: None,
        });
    }

    Ok("local".to_string())
}

fn require_roles_raw(
    auth: &AuthContext,
    allowed_roles: &[&str],
) -> std::result::Result<(), AuthError> {
    if allowed_roles.is_empty() {
        return Ok(());
    }
    if allowed_roles.iter().any(|role| auth.roles.contains(*role)) {
        return Ok(());
    }
    Err(AuthError {
        status: StatusCode::FORBIDDEN,
        code: "AUTH_ROLE_MISMATCH",
        message: "insufficient role for endpoint".to_string(),
        retry_after_seconds: None,
    })
}

fn require_endpoint_rate_limit_with_error(
    state: &AppState,
    auth: &AuthContext,
    endpoint_kind: &str,
) -> std::result::Result<(), (StatusCode, Json<ApiError>)> {
    if !state.rate_limiter.config.enabled {
        return Ok(());
    }
    let limit = match endpoint_kind {
        "run" => state.rate_limiter.config.per_run_endpoint_limit,
        "approval" => state.rate_limiter.config.per_approval_endpoint_limit,
        _ => state.rate_limiter.config.per_principal_limit,
    };
    let principal_scope = format!("{endpoint_kind}.principal");
    state
        .rate_limiter
        .check(
            &format!("{endpoint_kind}:principal:{}", auth.principal_id),
            limit,
        )
        .map_err(|err| {
            if err.code == "RATE_LIMITED" {
                api_error_rate_limited(
                    &err.message,
                    &principal_scope,
                    err.retry_after_seconds
                        .unwrap_or(state.rate_limiter.config.window_seconds),
                )
            } else {
                api_error_with_code(err.status, err.code, &err.message)
            }
        })?;
    let ip_scope = format!("{endpoint_kind}.ip");
    state
        .rate_limiter
        .check(&format!("{endpoint_kind}:ip:{}", auth.client_ip), limit)
        .map_err(|err| {
            if err.code == "RATE_LIMITED" {
                api_error_rate_limited(
                    &err.message,
                    &ip_scope,
                    err.retry_after_seconds
                        .unwrap_or(state.rate_limiter.config.window_seconds),
                )
            } else {
                api_error_with_code(err.status, err.code, &err.message)
            }
        })?;
    Ok(())
}

fn parse_bearer_token(headers: &HeaderMap) -> Option<&str> {
    let auth_value = headers.get(header::AUTHORIZATION)?.to_str().ok()?;
    let (scheme, token) = auth_value.split_once(' ')?;
    if scheme.eq_ignore_ascii_case("bearer") && !token.trim().is_empty() {
        Some(token.trim())
    } else {
        None
    }
}

fn cors_env_is_dev() -> bool {
    std::env::var("CARSINOS_ENV")
        .map(|value| {
            matches!(
                value.trim().to_ascii_lowercase().as_str(),
                "dev" | "development" | "local"
            )
        })
        .unwrap_or(true)
}

fn cors_allowed_origins() -> Vec<HeaderValue> {
    let configured = std::env::var("CARSINOS_CORS_ALLOW_ORIGINS")
        .unwrap_or_else(|_| "http://127.0.0.1:1420,http://localhost:1420".to_string());
    configured
        .split(',')
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .filter_map(|value| HeaderValue::from_str(value).ok())
        .collect()
}

fn build_cors_layer() -> CorsLayer {
    if cors_env_is_dev() {
        return CorsLayer::new()
            .allow_origin(Any)
            .allow_methods(Any)
            .allow_headers(Any);
    }

    let methods = [Method::GET, Method::POST, Method::PUT, Method::DELETE];
    let headers = [
        header::AUTHORIZATION,
        header::CONTENT_TYPE,
        HeaderName::from_static("x-request-id"),
    ];
    let layer = CorsLayer::new()
        .allow_methods(methods)
        .allow_headers(headers);
    let origins = cors_allowed_origins();
    if origins.is_empty() {
        layer
    } else {
        layer.allow_origin(origins)
    }
}

