fn load_agent_mail_message_response(
    state: &AppState,
    record: carsinos_storage::AgentMailMessageRecord,
) -> std::result::Result<AgentMailMessageResponse, (StatusCode, Json<ApiError>)> {
    let recipients = state
        .storage
        .list_agent_mail_message_recipients(&record.message_id)
        .map_err(|err| internal_err_with_error("loading agent-mail recipients failed", err))?
        .into_iter()
        .map(|item| AgentMailMessageRecipientResponse {
            recipient_principal: item.recipient_principal,
            delivered_at: item.delivered_at,
            acked_at: item.acked_at,
        })
        .collect::<Vec<_>>();
    let attachments = state
        .storage
        .list_agent_mail_attachments(&record.message_id)
        .map_err(|err| internal_err_with_error("loading agent-mail attachments failed", err))?
        .into_iter()
        .map(to_agent_mail_attachment_response)
        .collect::<Vec<_>>();
    Ok(AgentMailMessageResponse {
        message_id: record.message_id,
        thread_id: record.thread_id,
        sender_principal: record.sender_principal,
        sender_kind: record.sender_kind,
        body_text: record.body_text,
        metadata_json: record.metadata_json,
        created_at: record.created_at,
        recipients,
        attachments,
    })
}

fn load_board_detail_response(
    state: &AppState,
    board: BoardRecord,
) -> std::result::Result<BoardDetailResponse, (StatusCode, Json<ApiError>)> {
    let columns = state
        .storage
        .list_board_columns(&board.board_id)
        .map_err(|err| internal_err_with_error("listing board columns failed", err))?;
    let cards = state
        .storage
        .list_board_cards(&board.board_id)
        .map_err(|err| internal_err_with_error("listing board cards failed", err))?;

    let mut cards_out = Vec::new();
    for card in cards {
        let assets = state
            .storage
            .list_board_card_assets(&card.card_id)
            .map_err(|err| internal_err_with_error("listing board card assets failed", err))?;
        cards_out.push(to_board_card_response(card, assets));
    }

    let board_summary = to_board_summary_response(board, columns.len(), cards_out.len());
    Ok(BoardDetailResponse {
        board: board_summary,
        columns: columns.into_iter().map(to_board_column_response).collect(),
        cards: cards_out,
    })
}

