    #[allow(clippy::too_many_arguments)]
    fn build_test_context(
        allowlist: Vec<String>,
        numquam_client: Option<NumquamClient>,
        auth_mode: AuthMode,
        jwt_auth: Option<JwtAuthConfig>,
        auth_token: String,
        rate_limit_config: Option<RequestRateLimitConfig>,
        trusted_proxy_headers: bool,
        trusted_proxy_allowlist: HashSet<String>,
        plugin_manifests: Vec<CorePluginManifest>,
    ) -> TestContext {
        build_test_context_with_policy(
            allowlist,
            numquam_client,
            auth_mode,
            jwt_auth,
            auth_token,
            rate_limit_config,
            trusted_proxy_headers,
            trusted_proxy_allowlist,
            plugin_manifests,
            ExtensionSecurityPolicy::permissive_for_tests(),
        )
    }

    #[allow(clippy::too_many_arguments)]
    fn build_test_context_with_policy(
        allowlist: Vec<String>,
        numquam_client: Option<NumquamClient>,
        auth_mode: AuthMode,
        jwt_auth: Option<JwtAuthConfig>,
        auth_token: String,
        rate_limit_config: Option<RequestRateLimitConfig>,
        trusted_proxy_headers: bool,
        trusted_proxy_allowlist: HashSet<String>,
        plugin_manifests: Vec<CorePluginManifest>,
        extension_policy: ExtensionSecurityPolicy,
    ) -> TestContext {
        let temp_dir = TempDir::new().expect("tempdir");
        let paths = AppPaths::from_root(temp_dir.path().to_path_buf());
        carsinos_storage::init(&paths).expect("storage init");
        let (event_tx, _) = broadcast::channel(64);
        let storage = Storage::from_paths(&paths);
        let secret_store = SecretStore::from_env();
        let mut plugin_registry = PluginRegistry::new();
        for manifest in plugin_manifests {
            plugin_registry
                .register_manifest(manifest)
                .expect("register plugin manifest");
        }
        let extension_policy = Arc::new(extension_policy);
        let (hook_bus, hook_policy_denials) =
            build_hook_bus_from_registry(&plugin_registry, extension_policy.as_ref())
                .expect("build hook bus from registry");
        let hook_bus = Arc::new(hook_bus);
        let skill_registry = Arc::new(RwLock::new(SkillRegistry::new()));
        let tool_registry = Arc::new(ToolRegistry::permissive_for_tests());
        let tool_concurrency = Arc::new(Semaphore::new(64));
        let mut channel_tool_allowed_providers = HashSet::new();
        channel_tool_allowed_providers.insert("telegram".to_string());
        channel_tool_allowed_providers.insert("discord".to_string());
        let channel_runtime = Arc::new(ChannelRuntimeManager::default_with_storage(
            storage.clone(),
            secret_store.clone(),
        ));
        let rate_limiter = RequestRateLimiter {
            config: rate_limit_config.unwrap_or(RequestRateLimitConfig {
                enabled: false,
                window_seconds: 60,
                per_ip_limit: 10_000,
                per_principal_limit: 10_000,
                per_run_endpoint_limit: 10_000,
                per_approval_endpoint_limit: 10_000,
            }),
            counters: StdRwLock::new(HashMap::new()),
        };
        let trust_lock_path = trust_contract_lock_path(temp_dir.path());
        let trust_lock = build_runtime_trust_contract_lock_record(
            &default_runtime_config().global,
            "test",
            Utc::now().timestamp_millis(),
        )
        .expect("build runtime trust lock");
        persist_runtime_trust_contract_lock(&trust_lock_path, &trust_lock)
            .expect("persist runtime trust lock");

        let state = AppState {
            auth_mode,
            auth_token: Arc::new(auth_token),
            jwt_auth: jwt_auth.map(Arc::new),
            jwt_replay_jti: Arc::new(StdRwLock::new(HashMap::new())),
            rate_limiter: Arc::new(rate_limiter),
            trusted_proxy_headers,
            trusted_proxy_allowlist: Arc::new(trusted_proxy_allowlist),
            operator_allowlist: Arc::new(allowlist),
            provider_models_http_client: reqwest::Client::builder()
                .timeout(Duration::from_secs(15))
                .build()
                .expect("provider models http client"),
            provider_models_cache: Arc::new(RwLock::new(HashMap::new())),
            providers: ProviderRegistry::new(),
            tool_registry,
            tool_concurrency,
            channel_tool_allowed_providers: Arc::new(channel_tool_allowed_providers),
            channel_runtime,
            internal_channel_ingest_token: Arc::new(uuid::Uuid::new_v4().to_string()),
            tool_runner: LocalToolRunner::default(),
            secret_store: secret_store.clone(),
            oauth_sessions: Arc::new(RwLock::new(HashMap::new())),
            numquam_client,
            numquam_runtime_status: Arc::new(RwLock::new(NumquamRuntimeStatus::default())),
            plugin_registry: Arc::new(RwLock::new(plugin_registry)),
            hook_bus: hook_bus.clone(),
            skill_registry: skill_registry.clone(),
            extension_policy: extension_policy.clone(),
            storage: storage.clone(),
            metrics: Arc::new(GatewayMetrics::default()),
            event_tx,
            event_seq: Arc::new(AtomicU64::new(1)),
            started_at: Utc::now(),
            started_instant: Instant::now(),
            db_path: Arc::new(paths.db_path.display().to_string()),
            attachments_path: Arc::new(paths.attachments_dir.display().to_string()),
            session_run_lanes: Arc::new(SessionRunLaneManager::default()),
            tool_error_breaker: Arc::new(ToolErrorFingerprintBreaker::default()),
            plugin_runtime_health: Arc::new(StdRwLock::new(HashMap::new())),
            plugin_daemons: Arc::new(RwLock::new(HashMap::new())),
            scheduler_instance: Arc::new(SchedulerInstanceState::enabled_for_tests()),
            trust_contract_lock: Arc::new(RwLock::new(trust_lock)),
            trust_contract_lock_path: Arc::new(trust_lock_path.display().to_string()),
            state_dir: Arc::new(temp_dir.path().to_path_buf()),
        };
        state.channel_runtime.start_all();
        record_extension_hook_policy_denials(&state, &hook_policy_denials);

        let app = build_app(state.clone());
        TestContext {
            _temp_dir: temp_dir,
            app,
            state,
            storage,
            secret_store,
            hook_bus,
            skill_registry,
        }
    }

    #[derive(Clone)]
    struct NumquamStubConfig {
        context_text: String,
        context_degrade: bool,
        health_status: String,
        drop_required_operation: Option<String>,
    }

    impl NumquamStubConfig {
        fn healthy() -> Self {
            Self {
                context_text: "stored memory says user likes tea".to_string(),
                context_degrade: false,
                health_status: "ok".to_string(),
                drop_required_operation: None,
            }
        }
    }

    #[derive(Clone)]
    struct NumquamStubState {
        config: NumquamStubConfig,
        resolve_calls: Arc<AtomicU64>,
    }

    struct NumquamStubServer {
        base_url: String,
        resolve_calls: Arc<AtomicU64>,
        task: tokio::task::JoinHandle<()>,
    }

    impl Drop for NumquamStubServer {
        fn drop(&mut self) {
            self.task.abort();
        }
    }

    async fn spawn_numquam_stub(config: NumquamStubConfig) -> NumquamStubServer {
        let resolve_calls = Arc::new(AtomicU64::new(0));
        let app_state = NumquamStubState {
            config,
            resolve_calls: resolve_calls.clone(),
        };
        let app = Router::new()
            .route(
                "/api/integration/v1/context/build",
                post(numquam_stub_context_build),
            )
            .route(
                "/api/integration/v1/context/why",
                post(numquam_stub_context_why),
            )
            .route(
                "/api/integration/v1/writeback/propose",
                post(numquam_stub_writeback_propose),
            )
            .route(
                "/api/integration/v1/writeback/resolve",
                post(numquam_stub_writeback_resolve),
            )
            .route("/api/integration/v1/health", get(numquam_stub_health))
            .route(
                "/api/integration/v1/capabilities",
                get(numquam_stub_capabilities),
            )
            .route("/mcp", post(numquam_stub_mcp))
            .with_state(app_state);
        let listener = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind numquam stub");
        let addr = listener.local_addr().expect("numquam stub local addr");
        let task = tokio::spawn(async move {
            axum::serve(listener, app)
                .await
                .expect("numquam stub server");
        });
        NumquamStubServer {
            base_url: format!("http://{addr}"),
            resolve_calls,
            task,
        }
    }

    async fn numquam_stub_context_build(
        AxumState(state): AxumState<NumquamStubState>,
        Json(payload): Json<serde_json::Value>,
    ) -> Json<serde_json::Value> {
        let request_id = payload
            .get("request_id")
            .and_then(|value| value.as_str())
            .unwrap_or("req_stub_context")
            .to_string();
        let warnings = if state.config.context_degrade {
            vec![serde_json::json!({
                "warning_code": "TIMEOUT_RATE_HIGH",
                "message": "degraded in stub",
                "started_at_utc": Utc::now(),
                "scope": "context"
            })]
        } else {
            vec![]
        };
        let mut response = serde_json::json!({
            "schema_version": NUMQUAM_SCHEMA_VERSION,
            "request_id": request_id,
            "request_id_source": "client",
            "operation": "context.build",
            "ok": true,
            "degrade_mode": state.config.context_degrade,
            "warnings": warnings,
            "data": {
                "context_text": state.config.context_text,
                "evidence": [{
                    "evidence_id": "ev_stub_1",
                    "section": "fact",
                    "kind": "fact_card",
                    "summary": "User preference memory",
                    "citations": ["conv#1"],
                    "confidence": 0.88
                }],
                "route": "ltm_light",
                "confidence": 0.88
            }
        });
        if state.config.context_degrade {
            response["fallback_recommendation"] =
                serde_json::Value::String("stateless_chat".to_string());
        }
        Json(response)
    }

    async fn numquam_stub_writeback_propose(
        Json(payload): Json<serde_json::Value>,
    ) -> Json<serde_json::Value> {
        let request_id = payload
            .get("request_id")
            .and_then(|value| value.as_str())
            .unwrap_or("req_stub_propose")
            .to_string();
        let run_id = payload
            .get("run_id")
            .and_then(|value| value.as_str())
            .unwrap_or("run_stub");
        Json(serde_json::json!({
            "schema_version": NUMQUAM_SCHEMA_VERSION,
            "request_id": request_id,
            "request_id_source": "client",
            "operation": "writeback.propose",
            "ok": true,
            "degrade_mode": false,
            "warnings": [],
            "data": {
                "proposal_id": format!("proposal_{run_id}"),
                "status": "pending_review",
                "idempotent_replay": false,
                "audit_ref": format!("audit_{run_id}")
            }
        }))
    }

    async fn numquam_stub_context_why(
        Json(payload): Json<serde_json::Value>,
    ) -> Json<serde_json::Value> {
        let request_id = payload
            .get("request_id")
            .and_then(|value| value.as_str())
            .unwrap_or("req_stub_why")
            .to_string();
        let evidence_ids = payload
            .get("data")
            .and_then(|value| value.get("evidence_ids"))
            .and_then(|value| value.as_array())
            .cloned()
            .unwrap_or_default();
        let reasons = evidence_ids
            .iter()
            .filter_map(|item| item.as_str())
            .map(|id| {
                serde_json::json!({
                    "evidence_id": id,
                    "reason": format!("Stub reason for {}", id)
                })
            })
            .collect::<Vec<_>>();
        Json(serde_json::json!({
            "schema_version": NUMQUAM_SCHEMA_VERSION,
            "request_id": request_id,
            "request_id_source": "client",
            "operation": "context.why",
            "ok": true,
            "degrade_mode": false,
            "warnings": [],
            "data": {
                "reasons": reasons,
                "evidence": []
            }
        }))
    }

    async fn numquam_stub_writeback_resolve(
        AxumState(state): AxumState<NumquamStubState>,
        Json(payload): Json<serde_json::Value>,
    ) -> Json<serde_json::Value> {
        state.resolve_calls.fetch_add(1, Ordering::Relaxed);
        let request_id = payload
            .get("request_id")
            .and_then(|value| value.as_str())
            .unwrap_or("req_stub_resolve")
            .to_string();
        let data = payload
            .get("data")
            .cloned()
            .unwrap_or_else(|| serde_json::json!({}));
        let proposal_id = data
            .get("proposal_id")
            .and_then(|value| value.as_str())
            .unwrap_or("proposal_stub")
            .to_string();
        let decision = data
            .get("decision")
            .and_then(|value| value.as_str())
            .unwrap_or("approve");
        let status = if decision == "approve" {
            "approved"
        } else {
            "rejected"
        };
        Json(serde_json::json!({
            "schema_version": NUMQUAM_SCHEMA_VERSION,
            "request_id": request_id,
            "request_id_source": "client",
            "operation": "writeback.resolve",
            "ok": true,
            "degrade_mode": false,
            "warnings": [],
            "data": {
                "proposal_id": proposal_id,
                "status": status,
                "already_resolved": false,
                "resolved_at_utc": Utc::now(),
                "audit_ref": "audit_stub_resolve"
            }
        }))
    }

    async fn numquam_stub_health(
        AxumState(state): AxumState<NumquamStubState>,
    ) -> Json<serde_json::Value> {
        Json(serde_json::json!({
            "schema_version": NUMQUAM_SCHEMA_VERSION,
            "request_id": "req_stub_health",
            "request_id_source": "server_generated",
            "operation": "health.get",
            "ok": true,
            "degrade_mode": state.config.health_status != "ok",
            "warnings": [],
            "data": {
                "status": state.config.health_status,
                "uptime_ms": 1234,
                "dependencies": []
            }
        }))
    }

    async fn numquam_stub_capabilities(
        AxumState(state): AxumState<NumquamStubState>,
    ) -> Json<serde_json::Value> {
        let mut operations = vec![
            "context.build",
            "context.why",
            "writeback.propose",
            "writeback.resolve",
            "health.get",
            "capabilities.get",
        ];
        if let Some(drop_name) = state.config.drop_required_operation.as_ref() {
            operations.retain(|name| name != drop_name);
        }
        let ops = operations
            .into_iter()
            .map(|name| {
                serde_json::json!({
                    "name": name,
                    "enabled": true,
                    "requires_auth": true,
                    "required_roles": ["operator"],
                    "idempotent": false
                })
            })
            .collect::<Vec<_>>();
        Json(serde_json::json!({
            "schema_version": NUMQUAM_SCHEMA_VERSION,
            "request_id": "req_stub_capabilities",
            "request_id_source": "server_generated",
            "operation": "capabilities.get",
            "ok": true,
            "degrade_mode": false,
            "warnings": [],
            "data": {
                "contract_version": NUMQUAM_CONTRACT_VERSION,
                "supported_schema_versions": [NUMQUAM_CONTRACT_VERSION],
                "transports": ["http", "mcp"],
                "operations": ops
            }
        }))
    }

    async fn numquam_stub_mcp(
        AxumState(state): AxumState<NumquamStubState>,
        Json(payload): Json<serde_json::Value>,
    ) -> Json<serde_json::Value> {
        let id = payload
            .get("id")
            .cloned()
            .unwrap_or_else(|| serde_json::Value::Number(1u64.into()));
        let method = payload
            .get("method")
            .and_then(|value| value.as_str())
            .unwrap_or_default();
        if method == "initialize" {
            return Json(serde_json::json!({
                "jsonrpc": "2.0",
                "id": id,
                "result": {
                    "protocolVersion": "2024-11-05",
                    "capabilities": {}
                }
            }));
        }
        if method != "tools/call" {
            return Json(serde_json::json!({
                "jsonrpc": "2.0",
                "id": id,
                "error": {
                    "code": -32601,
                    "message": "method not found"
                }
            }));
        }

        let params = payload
            .get("params")
            .cloned()
            .unwrap_or_else(|| serde_json::json!({}));
        let name = params
            .get("name")
            .and_then(|value| value.as_str())
            .unwrap_or_default();
        let arguments = params
            .get("arguments")
            .cloned()
            .unwrap_or_else(|| serde_json::json!({}));
        let structured_content = match name {
            "integration.context.build" => {
                let request_id = arguments
                    .get("request_id")
                    .and_then(|value| value.as_str())
                    .unwrap_or("req_stub_mcp_context")
                    .to_string();
                serde_json::json!({
                    "schema_version": NUMQUAM_SCHEMA_VERSION,
                    "request_id": request_id,
                    "request_id_source": "client",
                    "operation": "context.build",
                    "ok": true,
                    "degrade_mode": state.config.context_degrade,
                    "warnings": [],
                    "data": {
                        "context_text": state.config.context_text,
                        "evidence": [{
                            "evidence_id": "ev_stub_1",
                            "section": "fact",
                            "kind": "fact_card",
                            "summary": "User preference memory",
                            "citations": ["conv#1"],
                            "confidence": 0.88
                        }],
                        "route": "ltm_light",
                        "confidence": 0.88
                    }
                })
            }
            "integration.context.why" => {
                let request_id = arguments
                    .get("request_id")
                    .and_then(|value| value.as_str())
                    .unwrap_or("req_stub_mcp_why")
                    .to_string();
                serde_json::json!({
                    "schema_version": NUMQUAM_SCHEMA_VERSION,
                    "request_id": request_id,
                    "request_id_source": "client",
                    "operation": "context.why",
                    "ok": true,
                    "degrade_mode": false,
                    "warnings": [],
                    "data": {
                        "reasons": [{
                            "evidence_id": "ev_stub_1",
                            "reason": "Stub why"
                        }],
                        "evidence": []
                    }
                })
            }
            "integration.writeback.propose" => {
                let request_id = arguments
                    .get("request_id")
                    .and_then(|value| value.as_str())
                    .unwrap_or("req_stub_mcp_propose")
                    .to_string();
                let run_id = arguments
                    .get("run_id")
                    .and_then(|value| value.as_str())
                    .unwrap_or("run_stub");
                serde_json::json!({
                    "schema_version": NUMQUAM_SCHEMA_VERSION,
                    "request_id": request_id,
                    "request_id_source": "client",
                    "operation": "writeback.propose",
                    "ok": true,
                    "degrade_mode": false,
                    "warnings": [],
                    "data": {
                        "proposal_id": format!("proposal_{run_id}"),
                        "status": "pending_review",
                        "idempotent_replay": false,
                        "audit_ref": format!("audit_{run_id}")
                    }
                })
            }
            "integration.writeback.resolve" => {
                state.resolve_calls.fetch_add(1, Ordering::Relaxed);
                let request_id = arguments
                    .get("request_id")
                    .and_then(|value| value.as_str())
                    .unwrap_or("req_stub_mcp_resolve")
                    .to_string();
                let proposal_id = arguments
                    .get("proposal_id")
                    .and_then(|value| value.as_str())
                    .unwrap_or("proposal_stub")
                    .to_string();
                let decision = arguments
                    .get("decision")
                    .and_then(|value| value.as_str())
                    .unwrap_or("approve");
                let status = if decision == "approve" {
                    "approved"
                } else {
                    "rejected"
                };
                serde_json::json!({
                    "schema_version": NUMQUAM_SCHEMA_VERSION,
                    "request_id": request_id,
                    "request_id_source": "client",
                    "operation": "writeback.resolve",
                    "ok": true,
                    "degrade_mode": false,
                    "warnings": [],
                    "data": {
                        "proposal_id": proposal_id,
                        "status": status,
                        "already_resolved": false,
                        "resolved_at_utc": Utc::now(),
                        "audit_ref": "audit_stub_resolve"
                    }
                })
            }
            "integration.health.get" => serde_json::json!({
                "schema_version": NUMQUAM_SCHEMA_VERSION,
                "request_id": "req_stub_mcp_health",
                "request_id_source": "server_generated",
                "operation": "health.get",
                "ok": true,
                "degrade_mode": state.config.health_status != "ok",
                "warnings": [],
                "data": {
                    "status": state.config.health_status,
                    "uptime_ms": 1234,
                    "dependencies": []
                }
            }),
            "integration.capabilities.get" => {
                let mut operations = vec![
                    "context.build",
                    "context.why",
                    "writeback.propose",
                    "writeback.resolve",
                    "health.get",
                    "capabilities.get",
                ];
                if let Some(drop_name) = state.config.drop_required_operation.as_ref() {
                    operations.retain(|name| name != drop_name);
                }
                let ops = operations
                    .into_iter()
                    .map(|op| serde_json::json!({"name": op, "enabled": true}))
                    .collect::<Vec<_>>();
                serde_json::json!({
                    "schema_version": NUMQUAM_SCHEMA_VERSION,
                    "request_id": "req_stub_mcp_capabilities",
                    "request_id_source": "server_generated",
                    "operation": "capabilities.get",
                    "ok": true,
                    "degrade_mode": false,
                    "warnings": [],
                    "data": {
                        "contract_version": NUMQUAM_CONTRACT_VERSION,
                        "supported_schema_versions": [NUMQUAM_CONTRACT_VERSION],
                        "transports": ["http", "mcp"],
                        "operations": ops
                    }
                })
            }
            _ => serde_json::json!({
                "schema_version": NUMQUAM_SCHEMA_VERSION,
                "request_id": "req_stub_unknown",
                "request_id_source": "server_generated",
                "operation": name,
                "ok": false,
                "degrade_mode": false,
                "warnings": [],
                "error": {
                    "code": "INVALID_INPUT",
                    "message": "unknown tool",
                    "retryable": false,
                    "operator_action": "use_supported_tool"
                }
            }),
        };
        Json(serde_json::json!({
            "jsonrpc": "2.0",
            "id": id,
            "result": {
                "structuredContent": structured_content,
                "content": [{
                    "type": "text",
                    "text": structured_content.to_string()
                }],
                "isError": false
            }
        }))
    }

